"use strict";(self.webpackChunkblogs=self.webpackChunkblogs||[]).push([["379"],{4369(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"linux-switch-mm","metadata":{"permalink":"/linux-switch-mm","source":"@site/blog/2026-06-20-linux-switch-mm/index.md","title":"\u5185\u6838\u6742\u8C08\uFF08\u4E00\uFF09\uFF1ALinux \u91CC\u662F\u600E\u4E48\u5207\u6362\u5730\u5740\u7A7A\u95F4\u7684\uFF1F","description":"CPU \u5207\u4EFB\u52A1\uFF1ATask A \u2192 Task B\uFF0C\u4E0D\u53EA\u662F\u6362\u5BC4\u5B58\u5668/\u6808/\u8C03\u5EA6\u4FE1\u606F\uFF0C\u8FD8\u5F97\u6362 CR3\u3001\u9875\u8868\u3001TLB \u4E0A\u4E0B\u6587\u3002\u4E0D\u7136 B \u4F1A\u770B\u89C1 A \u7684\u5730\u5740\u7A7A\u95F4\u3002","date":"2026-06-20T00:00:00.000Z","tags":[{"inline":false,"label":"Linux","permalink":"/tags/linux","description":"\u4E00\u4E9BLinux\u76F8\u5173\u7684\u6587\u7AE0"}],"readingTime":17.61,"hasTruncateMarker":true,"authors":[{"name":"Kun Luo","title":"Software Engineer","url":"https://github.com/luokn","page":{"permalink":"/authors/luokun"},"socials":{"github":"https://github.com/luokn","zhihu":"https://www.zhihu.com/people/luokn","email":"mailto:luokun485@gmail.com"},"imageURL":"/img/avatar.jpg","key":"luokun"}],"frontMatter":{"slug":"linux-switch-mm","title":"\u5185\u6838\u6742\u8C08\uFF08\u4E00\uFF09\uFF1ALinux \u91CC\u662F\u600E\u4E48\u5207\u6362\u5730\u5740\u7A7A\u95F4\u7684\uFF1F","authors":"luokun","tags":["linux"]},"unlisted":false,"nextItem":{"title":"MS-GAT\uFF1A\u7528\u591A\u5173\u7CFB\u56FE\u6CE8\u610F\u529B\u7F51\u7EDC\u5B66\u4E60\u591A\u5C42\u9762\u4EA4\u901A\u8026\u5408","permalink":"/multirelational_graph_attention_networks_paper"}},"content":":::tip\\nCPU \u5207\u4EFB\u52A1\uFF1ATask A \u2192 Task B\uFF0C\u4E0D\u53EA\u662F\u6362\u5BC4\u5B58\u5668/\u6808/\u8C03\u5EA6\u4FE1\u606F\uFF0C\u8FD8\u5F97\u6362 CR3\u3001\u9875\u8868\u3001TLB \u4E0A\u4E0B\u6587\u3002\u4E0D\u7136 B \u4F1A\u770B\u89C1 A \u7684\u5730\u5740\u7A7A\u95F4\u3002\\n\\n`switch_mm` \u8D1F\u8D23\u628A CPU \u4ECE\u65E7\u5730\u5740\u7A7A\u95F4\u5207\u5230\u65B0\u5730\u5740\u7A7A\u95F4\u3002\u672C\u6587\u5148\u56DE\u987E PCID/Local ASID \u673A\u5236\uFF0C\u518D\u804A Linux 6.15 \u5DE6\u53F3\u8FDB\u4E3B\u7EBF\u7684 Global ASID\u3002\\n\\n\uFF08\u6587\u4E2D\u4EE3\u7801\u57FA\u4E8E Linux 7.1 \u6E90\u7801\u6574\u7406\uFF0C\u76F8\u5173\u673A\u5236\u5728 6.15 \u5DF2\u5408\u5165\u4E3B\u7EBF\u3002\uFF09\\n:::\\n\\n![Banner](./local-pcid-tlb.drawio.svg)\\n\\n\\n{/* truncate */}\\n\\n## \u5148\u590D\u4E60\u4E00\u4E0B x86 \u7684 TLB \u4E0E PCID\\n\\n- \u6BCF\u4E2A\u903B\u8F91 CPU \u90FD\u6709\u72EC\u7ACB\u7684 **CR3**\u3001**CR4** \u4EE5\u53CA **TLB \u72B6\u6001**\u3002\u6240\u6709 CPU \u5171\u4EAB\u540C\u4E00\u5957\u7269\u7406\u5185\u5B58\uFF0C\u4F46\u5404\u81EA\u7EF4\u62A4\u81EA\u5DF1\u7684\u5730\u5740\u8F6C\u6362\u7F13\u5B58\u3002\\n\\n![CR3 \u5728 PCID \u542F\u7528\u540E\u7684\u4F4D\u57DF\u7ED3\u6784](./cr3-pcid-layout.drawio.svg)\\n\\n- \u56E0\u4E3A\u9875\u8868\u6839\u76EE\u5F55\uFF08PGD\uFF09\u6309 **4KB \u5BF9\u9F50**\uFF0CCR3 \u7684\u4F4E 12 \u4F4D\u539F\u672C\u5168\u662F 0\u3002x86 \u5F00\u542F PCID\uFF08`CR4.PCIDE=1`\uFF09\u540E\uFF0C\u5C31\u628A\u8FD9 12 \u4F4D\u590D\u7528\u6210 **PCID \u5B57\u6BB5**\u3002\\n\\n- TLB \u91CC\u5B58\u7684\u6761\u76EE\u4E0D\u662F\u7B80\u5355\u7684 VA \u2192 PA\uFF0C\u800C\u662F **(PCID, VA) \u2192 PA**\u3002\u4E0D\u540C\u5730\u5740\u7A7A\u95F4\u5373\u4F7F\u62E5\u6709\u76F8\u540C\u7684\u865A\u62DF\u5730\u5740\uFF0C\u53EA\u8981 PCID \u4E0D\u540C\uFF0C\u5C31\u53EF\u4EE5\u540C\u65F6\u9A7B\u7559\u5728 TLB \u91CC\u4E0D\u51B2\u7A81\u3002\\n\\n![\u540C\u4E00\u8FDB\u7A0B\u5728\u4E0D\u540C CPU \u4E0A\u4F7F\u7528\u4E0D\u540C Local PCID](./local-pcid-tlb.drawio.svg)\\n\\n- \u5199 CR3 \u662F\u4E00\u6761\u5E8F\u5217\u5316\u6307\u4EE4\uFF0C\u80FD\u591F\u4FDD\u8BC1\u65E7\u5730\u5740\u7A7A\u95F4\u4E0B\u7684\u5185\u5B58\u8BBF\u95EE\u5B8C\u6210\uFF0C\u4E4B\u540E\u518D\u5F00\u59CB\u57FA\u4E8E\u65B0 CR3 \u7684\u5730\u5740\u7FFB\u8BD1\u3002\u4E5F\u6B63\u56E0\u4E3A\u8FD9\u4E2A\u7279\u6027\uFF0C`switch_mm` \u88AB\u5185\u6838\u5F53\u6210\u4E00\u4E2A\u91CD\u8981\u7684\u5185\u5B58\u5C4F\u969C\u70B9\u3002\\n\\n- \u5728 PCID \u673A\u5236\u4E0B\uFF0C\u5199 CR3 \u65F6\u53EF\u4EE5\u8BBE\u7F6E **NOFLUSH \u4F4D**\uFF08bit 63\uFF09\uFF0C\u4FDD\u7559\u5BF9\u5E94 PCID \u4E0B\u5DF2\u6709\u7684 TLB \u7F13\u5B58\u3002\u5207\u6362\u5730\u5740\u7A7A\u95F4\u65F6\uFF0CCPU \u4E0D\u5FC5\u6BCF\u6B21\u90FD\u6E05\u7A7A TLB\uFF0C\u800C\u662F\u53EF\u4EE5\u5728\u591A\u4E2A\u5730\u5740\u7A7A\u95F4\u4E4B\u95F4\u590D\u7528\u4E4B\u524D\u7684\u6761\u76EE\u3002\\n\\n- \u5BF9\u4E8E\u8DE8 CPU \u7684 TLB shootdown\uFF0C\u9700\u8981\u53D1 **IPI** \uFF08Inter-Processor Interrupt\uFF09\u901A\u77E5\u8FDC\u7AEF CPU \u5237\u6389\u5BF9\u5E94 PCID \u7684\u6761\u76EE\uFF0C\u8FD9\u4F9D\u8D56\u64CD\u4F5C\u7CFB\u7EDF\u63D0\u4F9B\u7684\u4E2D\u65AD\u5904\u7406\u673A\u5236\u3002\u9664\u6B64\u4E4B\u5916\uFF0CAMD \u8FD8\u4E3A x86 \u63D0\u4F9B\u4E86 **INVLPGB**\uFF08broadcast TLB invalidation\uFF09\u6307\u4EE4\uFF0C\u53EF\u4EE5\u76F4\u63A5\u5931\u6548\u6307\u5B9A PCID \u4E0B\u7684\u6240\u6709\u6761\u76EE\uFF08\u6240\u6709 CPU\uFF09\uFF0C\u7701\u6389\u8F6F\u4EF6\u53D1 IPI \u7684\u5F00\u9500\u3002\u4E0D\u8FC7\u8FD9\u4E2A\u6307\u4EE4\u662F AMD Zen3 \u9996\u6B21\u5F15\u5165\u7684\uFF0CIntel \u8FD8\u4E0D\u652F\u6301\u3002\\n\\n\\n:::note[\u51E0\u4E2A\u5C0F\u6CE8]\\n\\n- \u73B0\u5728\u7684 CPU \u5DF2\u7ECF\u6709 5 \u7EA7\u9875\u8868\u652F\u6301\uFF0CVA \u4E5F\u5E72\u5230\u4E86 57 \u4F4D\uFF08`12 + 5 \xd7 9`\uFF09\u3002\u4E0D\u8FC7\u8FD9\u4E0D\u5F71\u54CD\u672C\u6587\u8981\u8BB2\u7684\u5207\u6362\u903B\u8F91\uFF0C\u4E0B\u9762\u9ED8\u8BA4\u6309 4 \u7EA7\u9875\u8868\u7406\u89E3\u3002\\n- Intel \u7684 LAM\uFF08Linear Address Masking\uFF09\u4F1A\u628A CR3 \u91CC\u6CA1\u7528\u5230\u7684\u4F4D\u63A9\u7801\u6389\uFF0C\u7ED9\u8F6F\u4EF6\u5F53\u5143\u6570\u636E\u7528\u3002\u9ED8\u8BA4\u5173\u95ED\uFF0C\u672C\u6587\u4E0D\u5C55\u5F00\u3002\\n- Linux 6.15 \u5DE6\u53F3\u8FDB\u4E3B\u7EBF\u7684 \\"Global ASID\\"\uFF0C\u5C31\u662F\u7528\u6765\u914D\u5408\u8FD9\u7C7B\u786C\u4EF6\u5E7F\u64AD\u5931\u6548\u7684\u3002\u4E0D\u8FC7 x86 \u7684 PCID \u4ECD\u7136\u53EA\u6709 4096 \u4E2A\uFF08PTI \u5F00\u542F\u65F6\u6298\u534A\uFF09\uFF0C\u6240\u4EE5\u5185\u6838\u91C7\u7528 **Local ASID \u4E3A\u4E3B\u3001\u7B26\u5408\u6761\u4EF6\u518D\u8FC1\u79FB\u5230 Global ASID** \u7684\u7B56\u7565\u3002\\n:::\\n\\n## \u6838\u5FC3\u6570\u636E\u7ED3\u6784\\n\\n### `mm_struct`\\n\\n`mm_struct` \u662F\u63CF\u8FF0\u4E00\u4E2A\u8FDB\u7A0B\u5730\u5740\u7A7A\u95F4\u6700\u6838\u5FC3\u7684\u7ED3\u6784\u3002\u8FD9\u91CC\u53EA\u770B\u8DDF\u5207\u6362\u76F8\u5173\u7684\u6210\u5458\uFF1A\\n\\n```c\\nstruct mm_struct {\\n    pgd_t *pgd;\\n\\n    /* \u67B6\u6784\u76F8\u5173\u7684\u4E0A\u4E0B\u6587 */\\n    mm_context_t context;\\n\\n    /*\\n     * mm_cpumask \u9700\u8981\u653E\u5728 mm_struct \u672B\u5C3E\uFF0C\\n     * \u56E0\u4E3A\u5B83\u7684\u5927\u5C0F\u968F nr_cpu_ids \u52A8\u6001\u53D8\u5316\u3002\\n     */\\n    char flexible_array[] __aligned(__alignof__(unsigned long));\\n};\\n```\\n\\n- `pgd`\uFF1A\u6307\u5411\u5F53\u524D mm \u7684\u9875\u8868\u6839\u76EE\u5F55\uFF08PGD\uFF09\u3002\u5207\u6362\u5730\u5740\u7A7A\u95F4\u65F6\uFF0C\u6700\u7EC8\u4F1A\u628A\u5B83\u7684\u7269\u7406\u5730\u5740\u5199\u8FDB CR3\u3002\\n- `context`\uFF1A\u67B6\u6784\u76F8\u5173\u7684\u4E0A\u4E0B\u6587\uFF0Cx86 \u4E0B\u5305\u542B **Unique ID**\u3001**TLB Generation**\u3001**Global ASID** \u7B49\u3002\\n- \u672B\u5C3E\u7684 `flexible_array` \u901A\u8FC7 `mm_cpumask(mm)` \u8BBF\u95EE\uFF0C\u662F\u4E00\u4E2A `cpumask_t`\uFF0C\u7528\u6765\u8BB0\u5F55\u54EA\u4E9B CPU \u6B63\u5728\u4F7F\u7528\u8FD9\u4E2A `mm`\u3002TLB shootdown \u5C31\u662F\u9760\u5B83\u77E5\u9053\u8BE5\u901A\u77E5\u8C01\u3002\\n\\n### `mm_context_t`\\n\\nx86 \u7684 `mm_context_t` \u5B9A\u4E49\u5728 `arch/x86/include/asm/mmu.h`\uFF0C\u8DDF\u5207\u6362\u76F8\u5173\u7684\u5B57\u6BB5\u5982\u4E0B\uFF08\u7701\u7565\u4E86 LDT\u3001PKU \u7B49\uFF09\uFF1A\\n\\n```c\\ntypedef struct {\\n    /*\\n     * ctx_id \u552F\u4E00\u6807\u8BC6\u4E00\u4E2A mm_struct\uFF0C\u4E0D\u4F1A\u590D\u7528\uFF0C0 \u4E5F\u4E0D\u662F\u6709\u6548\u503C\u3002\\n     */\\n    u64 ctx_id;\\n\\n    /*\\n     * \u4EFB\u4F55\u9700\u8981\u5237\u8FD9\u4E2A mm \u7684 TLB \u7684\u4EE3\u7801\uFF0C\u90FD\u4F1A\u5148\u6539\u9875\u8868\uFF0C\\n     * \u518D\u9012\u589E tlb_gen\uFF0C\u6700\u540E\u6267\u884C flush\u3002\u5E95\u5C42\u901A\u8FC7\u6BD4\u8F83 tlb_gen\\n     * \u5224\u65AD\u5F53\u524D CPU \u7F13\u5B58\u662F\u5426\u8FC7\u671F\u3002\\n     */\\n    atomic64_t tlb_gen;\\n\\n    /* \u4EE5\u4E0B\u4E24\u9879\u53EA\u5728\u914D\u7F6E BROADCAST_TLB_FLUSH \u65F6\u5B58\u5728 */\\n\\n    /*\\n     * \u975E\u96F6\u8868\u793A\u8FD9\u4E2A\u8FDB\u7A0B\u5728\u6240\u6709 CPU \u4E0A\u4F7F\u7528\u540C\u4E00\u4E2A ASID\uFF0C\\n     * \u4ECE\u800C\u53EF\u4EE5\u5229\u7528\u786C\u4EF6\u8FDC\u7A0B TLB \u5931\u6548\uFF0C\u6BD4\u5982 AMD INVLPGB\u3002\\n     */\\n    u16 global_asid;\\n\\n    /* \u6B63\u5728\u4ECE Local ASID \u8FC1\u79FB\u5230 Global ASID \u7684\u8FC7\u6E21\u6807\u5FD7 */\\n    bool asid_transition;\\n} mm_context_t;\\n```\\n\\n- `ctx_id`\uFF1A\u552F\u4E00\u7684 mm \u6807\u8BC6\uFF0CASID \u590D\u7528\u65F6\u9760\u5B83\u5224\u65AD TLB \u6761\u76EE\u662F\u5426\u8FD8\u5C5E\u4E8E\u540C\u4E00\u4E2A mm\u3002\\n- `tlb_gen`\uFF1A\u6BCF\u505A\u4E00\u6B21\u9875\u8868\u4FEE\u6539\u5E76\u51C6\u5907 flush\uFF0C\u8FD9\u4E2A\u503C\u5C31\u52A0 1\u3002CPU \u4E0A\u8BB0\u5F55\u7684 `tlb_gen` \u5982\u679C\u843D\u540E\uFF0C\u8BF4\u660E\u672C\u5730 TLB \u6709 stale \u6761\u76EE\u3002\\n- `global_asid` / `asid_transition`\uFF1AGlobal ASID \u76F8\u5173\uFF0C\u540E\u9762\u4E13\u95E8\u8BB2\u3002\\n\\n### `tlb_state`\\n\\n`tlb_state` \u662F**\u6BCF\u4E2A CPU \u79C1\u6709**\u7684\u72B6\u6001\uFF0C\u8BB0\u5F55\u5F53\u524D\u52A0\u8F7D\u7684\u662F\u54EA\u4E2A mm\u3001ASID \u662F\u4EC0\u4E48\u3001\u5404\u4E2A ASID \u69FD\u4F4D\u5BF9\u5E94\u7684 tlb_gen \u7B49\uFF1A\\n\\n```c\\nstruct tlb_state {\\n    /*\\n     * \u5F53\u672C\u5730\u4E2D\u65AD\u5F00\u542F\u65F6\uFF0Cloaded_mm \u5E94\u8BE5\u548C CR3 \u4FDD\u6301\u4E00\u81F4\u3002\\n     * \u5728 lazy TLB \u6A21\u5F0F\u4E0B\uFF0Cloaded_mm \u4ECD\u6307\u5411\u4E4B\u524D\u7684\u7528\u6237 mm\uFF0C\\n     * \u4F46 CR3 \u53EF\u80FD\u5DF2\u7ECF\u5207\u56DE init_mm\u3002\\n     */\\n    struct mm_struct *loaded_mm;\\n\\n#define LOADED_MM_SWITCHING ((struct mm_struct *)1UL)\\n\\n    /* \u6700\u540E\u4E00\u6B21\u8FD0\u884C\u7684\u7528\u6237 mm\uFF0C\u7528\u4E8E IBPB \u4F18\u5316 */\\n    union {\\n        struct mm_struct *last_user_mm;\\n        unsigned long   last_user_mm_spec;\\n    };\\n\\n    u16 loaded_mm_asid;    /* \u5F53\u524D CPU \u6B63\u5728\u4F7F\u7528\u7684 ASID */\\n    u16 next_asid;         /* \u4E0B\u4E00\u4E2A\u53EF\u5206\u914D\u7684\u52A8\u6001 ASID */\\n\\n    /*\\n     * \u5F53\u9875\u8868\u6539\u53D8\u65B9\u5F0F\u9700\u8981\u5931\u6548\u6240\u6709\u4E0A\u4E0B\u6587\u65F6\u7F6E\u4F4D\uFF0C\\n     * \u4E0B\u6B21\u5207\u4E0A\u4E0B\u6587\u65F6\u4F1A\u6E05\u6389\u975E\u5F53\u524D ctxs[] \u5BF9\u5E94\u7684\u7F13\u5B58\u3002\\n     */\\n    bool invalidate_other;\\n\\n#ifdef CONFIG_ADDRESS_MASKING\\n    u8 lam;\\n#endif\\n\\n    /* PTI \u4E0B\u8BB0\u5F55\u54EA\u4E9B\u7528\u6237 PCID \u4E0B\u6B21\u5207\u56DE\u7528\u6237\u6001\u65F6\u9700\u8981 flush */\\n    unsigned short user_pcid_flush_mask;\\n\\n    unsigned long cr4;\\n\\n    /*\\n     * \u6BCF\u4E2A ASID \u69FD\u4F4D\u4FDD\u5B58\u5B83\u5BF9\u5E94\u7684 mm ctx_id \u548C tlb_gen\u3002\\n     * ASID 0..5 \u79F0\u4E3A Dynamic ASID\uFF0C\u5171 TLB_NR_DYN_ASIDS=6 \u4E2A\u3002\\n     */\\n    struct tlb_context ctxs[TLB_NR_DYN_ASIDS];\\n};\\nDECLARE_PER_CPU_ALIGNED(struct tlb_state, cpu_tlbstate);\\n\\nstruct tlb_context {\\n    u64 ctx_id;\\n    u64 tlb_gen;\\n};\\n```\\n\\n\u6CE8\u610F\uFF1A`tlb_state` \u662F\u672C\u5730\u4FE1\u606F\uFF0C\u800C `mm_context_t` \u662F\u5168\u5C40\u4FE1\u606F\u3002\u5207\u6362\u65F6\u5C31\u662F\u901A\u8FC7\u6BD4\u8F83\u8FD9\u4E24\u8FB9\u7684 `tlb_gen` \u6765\u51B3\u5B9A\u8981\u4E0D\u8981 flush\u3002\\n\\n### `tlb_state_shared`\\n\\n```c\\nstruct tlb_state_shared {\\n    bool is_lazy;\\n};\\nDECLARE_PER_CPU_SHARED_ALIGNED(struct tlb_state_shared, cpu_tlbstate_shared);\\n```\\n\\n`is_lazy` \u4E4B\u6240\u4EE5\u653E\u5728\u72EC\u7ACB\u7684 shared per-cpu \u53D8\u91CF\u91CC\uFF0C\u662F\u56E0\u4E3A**\u5176\u4ED6 CPU \u5728\u8FDB\u884C TLB shootdown \u65F6\u9700\u8981\u8BFB\u5230\u5B83**\u3002`tlb_state` \u662F cache-line \u5BF9\u9F50\u7684 per-cpu \u6570\u636E\uFF0C\u8BBF\u95EE\u8DEF\u5F84\u66F4\u79C1\u6709\uFF1B\u628A `is_lazy` \u5355\u72EC\u62CE\u51FA\u6765\uFF0C\u8BA9\u8DE8 CPU \u8BFB\u53D6\u7684\u5F00\u9500\u66F4\u53EF\u63A7\u3002\\n\\n## \u5207\u6362\u6D41\u7A0B\uFF1A\u4ECE `schedule()` \u5230 `switch_mm_irqs_off`\\n\\n\u8C03\u5EA6\u5668\u5207\u6362\u4EFB\u52A1\u65F6\uFF0C\u8D70\u5230 `context_switch()`\uFF1A\\n\\n```c\\nschedule()\\n    |\\n    +- context_switch()\\n        |\\n        ?- \u5982\u679C next \u662F\u5185\u6838\u7EBF\u7A0B\uFF08next->mm == NULL\uFF09\\n        |       |\\n        |       +- enter_lazy_tlb(prev->active_mm, next)\\n        |\\n        ?- \u5982\u679C next \u662F\u7528\u6237\u4EFB\u52A1\\n        |       |\\n        |       +- membarrier_switch_mm(...)\\n        |       |\\n        |       +- switch_mm_irqs_off(prev->active_mm, next->mm, next)\\n        |\\n        +-- switch_to()      // \u5207\u5BC4\u5B58\u5668\u3001\u6808\\n```\\n\\n\u4E5F\u5C31\u662F\u8BF4\uFF0C\u8C03\u5EA6\u5668\u81EA\u5DF1\u5C31\u76F4\u63A5\u8C03\u7528 `switch_mm_irqs_off()`\uFF0C\u800C\u4E0D\u662F\u5148\u5305\u4E00\u5C42 `switch_mm()`\u3002`switch_mm()` \u8FD9\u4E2A\u5305\u88C5\u51FD\u6570\u4E3B\u8981\u7559\u7ED9\u4E34\u65F6 mm\u3001x86 \u7684 `leave_mm()` \u7B49\u573A\u666F\u7528\uFF1A\\n\\n```c\\nvoid switch_mm(struct mm_struct *prev, struct mm_struct *next,\\n               struct task_struct *tsk)\\n{\\n    unsigned long flags;\\n\\n    local_irq_save(flags);\\n    switch_mm_irqs_off(NULL, next, tsk);\\n    local_irq_restore(flags);\\n}\\n```\\n\\n### \u4E3A\u4EC0\u4E48 `switch_mm` \u5FC5\u987B\u5173\u4E2D\u65AD\uFF1F\\n\\n`switch_mm_irqs_off()` \u4E00\u8FDB\u6765\u5C31\u7528 `WARN_ON_ONCE(!irqs_disabled())` \u65AD\u8A00\u4E2D\u65AD\u5FC5\u987B\u662F\u5173\u7684\uFF1A\\n\\n```c\\nvoid switch_mm_irqs_off(struct mm_struct *unused, struct mm_struct *next,\\n                        struct task_struct *tsk)\\n{\\n    ...\\n    /* We don\'t want flush_tlb_func() to run concurrently with us. */\\n    if (IS_ENABLED(CONFIG_PROVE_LOCKING))\\n        WARN_ON_ONCE(!irqs_disabled());\\n    ...\\n}\\n```\\n\\n\u539F\u56E0\u5F88\u7B80\u5355\uFF1A\u5728\u5207\u6362\u7684\u90A3\u4E00\u5C0F\u6BB5\u65F6\u95F4\u91CC\uFF0C`cpu_tlbstate.loaded_mm`\u3001`CR3`\u3001`mm_cpumask()` \u4E09\u8005\u5FC5\u987B\u4FDD\u6301\u4E00\u81F4\u3002\u5982\u679C\u8FD9\u65F6\u5019\u6765\u4E86\u4E2D\u65AD\uFF0C\u5C24\u5176\u662F **TLB shootdown IPI**\uFF0C\u89C2\u5BDF\u5230\u7684\u72B6\u6001\u53EF\u80FD\u5C31\u662F\u4E2D\u95F4\u6001\u3002\\n\\n\u5177\u4F53\u6765\u8BF4\uFF0Cx86 \u7684 `flush_tlb_func()` \u672C\u8EAB\u4E5F\u662F\u4E2D\u65AD\u4E0A\u4E0B\u6587\u91CC\u8DD1\u7684\uFF08\u5B83\u9760 IPI \u89E6\u53D1\uFF09\uFF0C\u5B83\u4E00\u4E0A\u6765\u4F1A\u8BFB `cpu_tlbstate.loaded_mm` \u548C `cpu_tlbstate_shared.is_lazy`\u3002\u5982\u679C `switch_mm` \u6267\u884C\u5230\u4E00\u534A\u3001IRQ \u7A81\u7136\u6253\u5F00\uFF0CIPI \u5904\u7406\u5668\u770B\u5230\u7684 `loaded_mm` \u548C\u5B9E\u9645 CR3 \u4E0D\u4E00\u81F4\uFF0C\u5C31\u53EF\u80FD\u505A\u51FA\u9519\u8BEF\u5224\u65AD\uFF1A\\n\\n- \u4EE5\u4E3A\u67D0\u4E2A mm \u8FD8\u5728\u8FD0\u884C\uFF0C\u7ED3\u679C\u6CA1\u5237\uFF1B\\n- \u4EE5\u4E3A\u5DF2\u7ECF\u5207\u8D70\u4E86\uFF0C\u7ED3\u679C\u5237\u4E86\u4E0D\u8BE5\u5237\u7684\uFF1B\\n- \u66F4\u9EBB\u70E6\u7684\u662F `nmi_uaccess_okay()`\uFF1ANMI \u5904\u7406\u7A0B\u5E8F\u8981\u901A\u8FC7 `loaded_mm` \u5224\u65AD\u80FD\u4E0D\u80FD\u5B89\u5168\u8BBF\u95EE\u7528\u6237\u7A7A\u95F4\uFF0C\u5982\u679C `loaded_mm` \u548C CR3 \u5BF9\u4E0D\u4E0A\uFF0C\u5C31\u53EF\u80FD\u8BBF\u95EE\u5230\u9519\u8BEF\u7684\u5730\u5740\u7A7A\u95F4\u3002\\n\\n\u6240\u4EE5\u4EE3\u7801\u5728\u771F\u6B63\u5199 CR3 \u4E4B\u524D\uFF0C\u5148\u628A `loaded_mm` \u8BBE\u6210\u4E00\u4E2A\u7279\u6B8A\u54E8\u5175 `LOADED_MM_SWITCHING`\uFF1A\\n\\n```c\\n/*\\n * Indicate that CR3 is about to change. nmi_uaccess_okay()\\n * and others are sensitive to the window where mm_cpumask(),\\n * CR3 and cpu_tlbstate.loaded_mm are not all in sync.\\n */\\nthis_cpu_write(cpu_tlbstate.loaded_mm, LOADED_MM_SWITCHING);\\n```\\n\\n\u8FD9\u6BB5\u7A97\u53E3\u671F\u5FC5\u987B\u539F\u5B50\u7684\uFF0C\u529E\u6CD5\u5C31\u662F**\u6574\u4E2A `switch_mm_irqs_off()` \u90FD\u5173\u4E2D\u65AD\u6267\u884C**\u3002\u7B49 CR3 \u5199\u5B8C\u4E86\u3001`loaded_mm` \u548C `loaded_mm_asid` \u90FD\u66F4\u65B0\u5B8C\u6BD5\uFF0C\u518D\u5F00\u4E2D\u65AD\u3002\\n\\n\u53E6\u5916\uFF0C\u5199 CR3 \u672C\u8EAB\u8FD8\u81EA\u5E26**\u5168\u5185\u5B58\u5C4F\u969C + \u6838\u5FC3\u5E8F\u5217\u5316**\u6548\u679C\uFF0C`membarrier()` \u7CFB\u7EDF\u8C03\u7528\u4F9D\u8D56\u8FD9\u4E00\u70B9\u6765\u4FDD\u8BC1 `rq->curr` \u66F4\u65B0\u548C\u8FD4\u56DE\u7528\u6237\u6001\u4E4B\u95F4\u7684\u987A\u5E8F\u3002\u6240\u4EE5 `switch_mm` \u4E0D\u4EC5\u662F\u5730\u5740\u7A7A\u95F4\u5207\u6362\u70B9\uFF0C\u4E5F\u662F\u5185\u6838\u91CC\u7684\u4E00\u4E2A\u5173\u952E\u540C\u6B65\u70B9\u3002\\n\\n### \u5FEB\u8DEF\u5F84\uFF1A`prev == next`\\n\\n\u5982\u679C `cpu_tlbstate.loaded_mm == next`\uFF0C\u8BF4\u660E\u8FD9\u4E2A CPU \u5DF2\u7ECF\u52A0\u8F7D\u4E86\u76EE\u6807 mm\uFF0C\u4E0D\u4E00\u5B9A\u9700\u8981\u91CD\u65B0\u5199 CR3\u3002\\n\\n```c\\nif (prev == next) {\\n    /*\\n     * \u5982\u679C\u5F53\u524D mm \u6B63\u5728\u5F80 Global ASID \u8FC1\u79FB\uFF0C\\n     * \u5373\u4F7F prev == next \u4E5F\u8981\u628A CR3 \u6362\u6210 Global ASID\u3002\\n     */\\n    if (mm_needs_global_asid(next, prev_asid)) {\\n        next_tlb_gen = atomic64_read(&next->context.tlb_gen);\\n        ns = choose_new_asid(next, next_tlb_gen);\\n        goto reload_tlb;\\n    }\\n\\n    /*\\n     * \u5DF2\u7ECF\u5728\u7528 Global ASID\uFF1A\u786C\u4EF6\u5E7F\u64AD\u5931\u6548\u4F1A\u4FDD\u8BC1\u6240\u6709 CPU \u7684 TLB\\n     * \u90FD\u662F\u6700\u65B0\u7684\uFF0C\u76F4\u63A5\u8FD4\u56DE\u3002\\n     */\\n    if (is_global_asid(prev_asid))\\n        return;\\n\\n    /*\\n     * \u975E lazy \u6A21\u5F0F\uFF1A\u540C\u4E00\u4E2A\u8FDB\u7A0B\u5185\u7684\u7EBF\u7A0B\u5207\u6362\uFF0C\u4E0D\u9700\u8981 flush\u3002\\n     */\\n    if (!was_lazy)\\n        return;\\n\\n    /*\\n     * \u4E4B\u524D\u662F lazy \u6A21\u5F0F\uFF0C\u9700\u8981\u68C0\u67E5 tlb_gen \u5224\u65AD\u662F\u5426\u9700\u8981\u8865\u5237\u3002\\n     */\\n    smp_mb();\\n    next_tlb_gen = atomic64_read(&next->context.tlb_gen);\\n    if (this_cpu_read(cpu_tlbstate.ctxs[prev_asid].tlb_gen) ==\\n            next_tlb_gen)\\n        return;\\n\\n    /* lazy \u671F\u95F4\u9875\u8868\u88AB\u6539\u8FC7\uFF0Cfall through \u53BB\u6162\u8DEF\u5F84\u8865\u5237 */\\n    ns.asid = prev_asid;\\n    ns.need_flush = true;\\n}\\n```\\n\\n### \u6162\u8DEF\u5F84\uFF1A\u771F\u6B63\u5207\u6362 mm\\n\\n\u5F53 `prev != next` \u65F6\uFF0C\u6267\u884C\u771F\u6B63\u7684\u5207\u6362\uFF1A\\n\\n```c\\n} else {\\n    /* \u8FDB\u7A0B\u95F4\u5207\u6362\u65F6\u53EF\u80FD\u9700\u8981 IBPB/L1D flush \u7B49\u7F13\u89E3\u63AA\u65BD */\\n    cond_mitigation(tsk);\\n\\n    /*\\n     * \u6807\u8BB0 CR3 \u5373\u5C06\u6539\u53D8\u3002nmi_uaccess_okay() \u7B49\u4EE3\u7801\u5BF9\\n     * mm_cpumask()\u3001CR3\u3001loaded_mm \u4E0D\u4E00\u81F4\u7684\u7A97\u53E3\u5F88\u654F\u611F\u3002\\n     */\\n    this_cpu_write(cpu_tlbstate.loaded_mm, LOADED_MM_SWITCHING);\\n\\n    /*\\n     * \u786E\u4FDD\u672C CPU \u5728 next \u7684 mm_cpumask \u91CC\uFF0C\u8FD9\u6837\u540E\u7EED\u7684 TLB shootdown\\n     * \u624D\u80FD\u901A\u77E5\u5230\u6211\u4EEC\u3002cpumask_set_cpu() \u7684\u539F\u5B50\u5199\u81EA\u5E26 smp_mb()\u3002\\n     */\\n    if (next != &init_mm && !cpumask_test_cpu(cpu, mm_cpumask(next)))\\n        cpumask_set_cpu(cpu, mm_cpumask(next));\\n    else\\n        smp_mb();\\n\\n    next_tlb_gen = atomic64_read(&next->context.tlb_gen);\\n    ns = choose_new_asid(next, next_tlb_gen);\\n}\\n```\\n\\n\u7136\u540E\u7EDF\u4E00\u8D70\u5230 `reload_tlb:`\uFF1A\\n\\n```c\\nreload_tlb:\\nnew_lam = mm_lam_cr3_mask(next);\\nif (ns.need_flush) {\\n    VM_WARN_ON_ONCE(is_global_asid(ns.asid));\\n    this_cpu_write(cpu_tlbstate.ctxs[ns.asid].ctx_id, next->context.ctx_id);\\n    this_cpu_write(cpu_tlbstate.ctxs[ns.asid].tlb_gen, next_tlb_gen);\\n    load_new_mm_cr3(next->pgd, ns.asid, new_lam, true);\\n} else {\\n    /* \u8FD9\u4E2A ASID \u5DF2\u7ECF\u662F\u6700\u65B0\u7684\uFF0C\u5199 CR3 \u65F6\u5E26 NOFLUSH */\\n    load_new_mm_cr3(next->pgd, ns.asid, new_lam, false);\\n}\\n\\n/* \u786E\u4FDD CR3 \u5199\u5B8C\u540E\u624D\u66F4\u65B0 loaded_mm */\\nbarrier();\\n\\nthis_cpu_write(cpu_tlbstate.loaded_mm, next);\\nthis_cpu_write(cpu_tlbstate.loaded_mm_asid, ns.asid);\\ncpu_tlbstate_update_lam(new_lam, mm_untag_mask(next));\\n\\nif (next != prev) {\\n    cr4_update_pce_mm(next);\\n    switch_ldt(prev, next);\\n}\\n```\\n\\n\u6CE8\u610F `ns.need_flush` \u5BF9 Global ASID \u6765\u8BF4\u6C38\u8FDC\u662F `false`\uFF0C\u56E0\u4E3A Global ASID \u7531\u786C\u4EF6\u5E7F\u64AD\u5931\u6548\u4FDD\u8BC1\u4E00\u81F4\u6027\uFF0C\u4E0D\u9700\u8981\u5728\u5199 CR3 \u65F6\u6E05 TLB\u3002\\n\\n## ASID \u4E0E PCID \u7684\u5BF9\u5E94\u5173\u7CFB\\n\\nLinux \u5185\u90E8\u628A \\"ASID\\" \u548C \\"PCID\\" \u8FD9\u4E24\u4E2A\u540D\u5B57\u533A\u5206\u5F00\uFF0C\u907F\u514D\u641E\u6DF7\uFF1A\\n\\n```c\\n/*\\n * ASID - [0, TLB_NR_DYN_ASIDS-1]\\n *        \u6BCF\u4E2A CPU \u672C\u5730\u52A8\u6001\u5206\u914D\u7684 mm \u6807\u8BC6\u3002\\n *        [TLB_NR_DYN_ASIDS, MAX_ASID_AVAILABLE-1]\\n *        \u5168\u5C40 ASID\uFF0C\u6240\u6709 CPU \u4E0A\u76F8\u540C\u3002\\n *\\n * kPCID - [1, MAX_ASID_AVAILABLE]\\n *         \u5B9E\u9645\u5199\u5165 CR3 \u7684 PCID \u503C\uFF0C\u7B49\u4E8E ASID + 1\uFF0C\u56E0\u4E3A PCID 0 \u88AB\u4FDD\u7559\u3002\\n *\\n * uPCID - \u5982\u679C\u5F00\u542F KPTI\uFF0C\u6BCF\u4E2A mm \u8FD8\u6709\u5BF9\u5E94\u7684\u7528\u6237\u6001 PCID\uFF0C\\n *         \u901A\u8FC7\u7ED9 kPCID \u7F6E\u4E0A PTI_USER_PCID_BIT \u5F97\u5230\u3002\\n */\\n```\\n\\n`build_cr3` \u548C `build_cr3_noflush` \u8D1F\u8D23\u62FC CR3 \u503C\uFF1A\\n\\n```c\\nstatic inline unsigned long build_cr3(pgd_t *pgd, u16 asid, unsigned long lam)\\n{\\n    unsigned long cr3 = __sme_pa(pgd) | lam;\\n\\n    if (static_cpu_has(X86_FEATURE_PCID)) {\\n        cr3 |= kern_pcid(asid);\\n    } else {\\n        VM_WARN_ON_ONCE(asid != 0);\\n    }\\n\\n    return cr3;\\n}\\n\\nstatic inline unsigned long build_cr3_noflush(pgd_t *pgd, u16 asid,\\n                          unsigned long lam)\\n{\\n    VM_WARN_ON_ONCE(!boot_cpu_has(X86_FEATURE_PCID));\\n    return build_cr3(pgd, asid, lam) | CR3_NOFLUSH;\\n}\\n```\\n\\n`kern_pcid()` \u505A ASID \u2192 kPCID \u7684\u6620\u5C04\uFF1A\\n\\n```c\\nstatic inline u16 kern_pcid(u16 asid)\\n{\\n    VM_WARN_ON_ONCE(asid > MAX_ASID_AVAILABLE);\\n\\n#ifdef CONFIG_MITIGATION_PAGE_TABLE_ISOLATION\\n    BUILD_BUG_ON(TLB_NR_DYN_ASIDS >= (1 << X86_CR3_PTI_PCID_USER_BIT));\\n    VM_WARN_ON_ONCE(asid & (1 << X86_CR3_PTI_PCID_USER_BIT));\\n#endif\\n\\n    /*\\n     * \u52A0 1 \u662F\u4E3A\u4E86\u628A PCID 0 \u817E\u51FA\u6765\uFF0C\u7559\u7ED9\u4E0D\u61C2 PCID \u7684\u4EE3\u7801\u8DEF\u5F84\u4F7F\u7528\u3002\\n     * \u8FD9\u6837\u4E07\u4E00\u6709\u8C01 save/restore CR3 \u65F6\u628A PCID \u4E22\u4E86\uFF0C\u4E5F\u4E0D\u4F1A\u6C61\u67D3 ASID 0 \u7684\u7F13\u5B58\u3002\\n     */\\n    return asid + 1;\\n}\\n```\\n\\n\u6240\u4EE5\u6620\u5C04\u5173\u7CFB\u662F\uFF1A\\n\\n| \u6982\u5FF5 | \u8303\u56F4 | \u8BF4\u660E |\\n|------|------|------|\\n| Dynamic ASID | 0 ~ 5 | \u6BCF\u4E2A CPU \u672C\u5730\u7F13\u5B58\u6700\u8FD1\u7528\u8FC7\u7684\u51E0\u4E2A mm |\\n| Global ASID | 6 ~ MAX_ASID_AVAILABLE-1 | \u6240\u6709 CPU \u4E0A\u76F8\u540C\uFF0C\u7ED9\u591A\u7EBF\u7A0B\u8FDB\u7A0B\u7528 |\\n| kPCID | ASID + 1 | \u5B9E\u9645\u5199\u5165 CR3 \u7684 kernel PCID |\\n| uPCID | kPCID \\\\| PTI bit | \u5982\u679C\u5F00\u4E86 PTI\uFF0C\u7528\u6237\u6001 PCID \u53E6\u52A0\u4E00\u4F4D\u533A\u5206 |\\n\\n\u786C\u4EF6\u867D\u7136\u6709 4096 \u4E2A PCID\uFF08PTI \u5F00\u542F\u65F6\u53EF\u7528 2048 \u4E2A\uFF09\uFF0C\u4F46 Linux \u5E76\u4E0D\u4F1A\u7ED9\u6BCF\u4E2A\u8FDB\u7A0B\u4E00\u4E2A\u72EC\u7ACB\u7684 ASID\u3002\u672C\u5730\u53EA\u7559 6 \u4E2A Dynamic ASID \u505A\u7F13\u5B58\uFF0C\u518D\u62FF\u4E00\u90E8\u5206\u9AD8\u7F16\u53F7 ASID \u505A Global ASID\uFF1B\u5269\u4E0B\u7684 ASID \u7A7A\u95F4\u5E76\u4E0D\u4F7F\u7528\u3002\\n\\n:::caution\\n\u5982\u679C\u5185\u6838\u5F00\u542F PTI\uFF0Cx86 \u7684 Global ASID/INVLPGB \u8DEF\u5F84\u901A\u5E38\u4F1A\u88AB\u7981\u7528\uFF086.15 \u7684 stable \u4FEE\u590D\u5DF2\u7ECF\u660E\u786E `Disable INVLPGB when PTI is enabled`\uFF09\u3002\u4E5F\u5C31\u662F\u8BF4\uFF0CPTI + Global ASID \u76EE\u524D\u57FA\u672C\u4E92\u65A5\u3002\\n:::\\n\\n## Lazy TLB\uFF1A\u5185\u6838\u7EBF\u7A0B\u7684\u201C\u5077\u61D2\u201D\u4E0E\u201C\u56DE\u8865\u201D\\n\\n\u5185\u6838\u7EBF\u7A0B\u6CA1\u6709\u81EA\u5DF1\u7684\u7528\u6237\u5730\u5740\u7A7A\u95F4\uFF08`next->mm == NULL`\uFF09\u3002\u8C03\u5EA6\u5668\u5728\u5207\u5230\u5185\u6838\u7EBF\u7A0B\u65F6\uFF0C\u4E0D\u4F1A\u8C03\u7528 `switch_mm`\uFF0C\u800C\u662F\u8D70 `enter_lazy_tlb()`\uFF1A\\n\\n```c\\nstatic __always_inline void enter_lazy_tlb(struct mm_struct *mm, struct task_struct *tsk)\\n{\\n    if (this_cpu_read(cpu_tlbstate.loaded_mm) == &init_mm)\\n        return;\\n\\n    this_cpu_write(cpu_tlbstate_shared.is_lazy, true);\\n}\\n```\\n\\n\u5B83\u53EA\u628A `is_lazy` \u7F6E\u4E3A `true`\uFF0C**\u4E0D\u5207\u6362 CR3**\u3002CPU \u7EE7\u7EED\u590D\u7528\u4E0A\u4E00\u4E2A\u7528\u6237\u8FDB\u7A0B\u7684\u9875\u8868\uFF0C\u8FD9\u6837\u7701\u4E86\u4E00\u6B21 CR3 \u5199\u548C TLB \u5237\u65B0\u3002\\n\\n```text\\nProcess A (mm1)\\n    \u2193\\nkworker            // \u53EA set is_lazy\uFF0CCR3 \u4ECD\u6307\u5411 mm1\\n    \u2193\\nProcess A (mm1)    // \u5207\u56DE\u6765\u65F6\u6839\u636E was_lazy \u5224\u65AD\u8981\u4E0D\u8981\u8865\u5237\\n```\\n\\n![Lazy TLB \u7684\u8DF3\u8FC7\u4E0E\u56DE\u8865](./lazy-tlb-flow.drawio.svg)\\n\\n### \u4E3A\u4EC0\u4E48 Lazy CPU \u53EF\u4EE5\u4E0D\u88AB shootdown\uFF1F\\n\\n\u5F53\u67D0\u4E2A CPU \u5904\u4E8E lazy \u6A21\u5F0F\u65F6\uFF0C`should_flush_tlb()` \u4F1A\u8DF3\u8FC7\u5B83\uFF1A\\n\\n```c\\nstatic bool should_flush_tlb(int cpu, void *data)\\n{\\n    struct mm_struct *loaded_mm = per_cpu(cpu_tlbstate.loaded_mm, cpu);\\n    struct flush_tlb_info *info = data;\\n\\n    /*\\n     * \u6309 switch_mm_irqs_off() \u91CC\u7684\u5199\u987A\u5E8F\uFF0C\u786E\u4FDD\u8BFB\u5230\u7684 is_lazy\\n     * \u81F3\u5C11\u548C loaded_mm \u4E00\u6837\u65B0\u3002\\n     */\\n    smp_rmb();\\n\\n    /* Lazy TLB \u4F1A\u5728\u4E0B\u4E00\u6B21\u4E0A\u4E0B\u6587\u5207\u6362\u65F6\u81EA\u5DF1\u5237\u65B0\u3002 */\\n    if (per_cpu(cpu_tlbstate_shared.is_lazy, cpu))\\n        return false;\\n\\n    /* \u6CA1\u6709 mm \u8868\u793A\u662F\u5185\u6838\u5185\u5B58 flush */\\n    if (!info->mm)\\n        return true;\\n\\n    /* \u5207\u6362\u7A97\u53E3\u671F\u6309\u6700\u574F\u60C5\u51B5\u5904\u7406 */\\n    if (loaded_mm == LOADED_MM_SWITCHING)\\n        return true;\\n\\n    /* \u76EE\u6807 mm \u6B63\u5728\u8FD9\u4E2A CPU \u4E0A\u8DD1\uFF0C\u4E14\u4E0D\u662F lazy */\\n    if (loaded_mm == info->mm)\\n        return true;\\n\\n    /* \u5728 cpumask \u91CC\u4F46\u6CA1\u52A0\u8F7D\uFF1F\u5468\u671F\u6027 trim */\\n    if (info->trim_cpumask)\\n        return true;\\n\\n    return false;\\n}\\n```\\n\\n\u8DF3\u8FC7\u7684\u524D\u63D0\u662F\uFF1A**\u9875\u8868\u672C\u8EAB\u4E0D\u4F1A\u88AB\u91CA\u653E**\u3002\u5982\u679C `info->freed_tables` \u4E3A\u771F\uFF0C\u8BF4\u660E\u65E7\u9875\u8868\u9875\u53EF\u80FD\u88AB\u56DE\u6536\uFF0Clazy CPU  speculative \u8BBF\u95EE\u5230\u65B0\u5185\u5BB9\u4F1A\u51FA\u4E71\u5B50\uFF0C\u8FD9\u65F6\u5FC5\u987B\u5F3A\u5236\u53D1 IPI\uFF1A\\n\\n```c\\nif (info->freed_tables || mm_in_asid_transition(info->mm))\\n    on_each_cpu_mask(cpumask, flush_tlb_func, (void *)info, true);\\nelse\\n    on_each_cpu_cond_mask(should_flush_tlb, flush_tlb_func,\\n                          (void *)info, 1, cpumask);\\n```\\n\\n### \u4ECE lazy \u5207\u56DE\u771F\u5B9E mm \u65F6\u7684\u56DE\u8865\\n\\n`switch_mm_irqs_off()` \u4E00\u8FDB\u6765\u5C31\u8BFB `was_lazy`\uFF0C\u5982\u679C\u662F lazy\uFF0C\u5148\u6E05\u6389\u6807\u5FD7\uFF1A\\n\\n```c\\nbool was_lazy = this_cpu_read(cpu_tlbstate_shared.is_lazy);\\n...\\nif (was_lazy)\\n    this_cpu_write(cpu_tlbstate_shared.is_lazy, false);\\n```\\n\\n\u5728 `prev == next` \u7684\u5FEB\u8DEF\u5F84\u91CC\uFF0C\u5982\u679C `was_lazy` \u4E3A\u771F\uFF0C\u4F1A\u6BD4\u8F83\u672C\u5730 `tlb_gen` \u548C `mm->context.tlb_gen`\u3002\u5982\u679C lazy \u671F\u95F4\u9875\u8868\u88AB\u6539\u8FC7\uFF0C\u5C31 fall through \u5230\u6162\u8DEF\u5F84\uFF0C\u91CD\u65B0\u52A0\u8F7D CR3 \u5E76\u5237\u65B0 TLB\u3002\\n\\n### `leave_mm()`\\n\\n\u5982\u679C\u67D0\u4E2A\u4EE3\u7801\u8DEF\u5F84\u4E0D\u80FD\u5BB9\u5FCD lazy\uFF08\u6BD4\u5982 `use_temporary_mm()`\uFF09\uFF0C\u53EF\u4EE5\u4E3B\u52A8\u8C03\u7528 `leave_mm()`\uFF0C\u5F3A\u5236\u5207\u5230 `init_mm`\uFF1A\\n\\n```c\\nvoid leave_mm(void)\\n{\\n    struct mm_struct *loaded_mm = this_cpu_read(cpu_tlbstate.loaded_mm);\\n\\n    if (loaded_mm == &init_mm)\\n        return;\\n\\n    WARN_ON(!this_cpu_read(cpu_tlbstate_shared.is_lazy));\\n    switch_mm(NULL, &init_mm, NULL);\\n}\\n```\\n\\n## Global ASID \u7684\u6E10\u8FDB\u5F0F\u8FC1\u79FB\\n\\nGlobal ASID \u7684\u51FA\u73B0\u662F\u4E3A\u4E86\u89E3\u51B3\u4E00\u4E2A\u95EE\u9898\uFF1A**\u591A\u7EBF\u7A0B\u8FDB\u7A0B\u5728\u591A\u4E2A CPU \u4E0A\u540C\u65F6\u8DD1\u65F6\uFF0C\u6BCF\u6B21\u9875\u8868\u4FEE\u6539\u90FD\u8981\u7ED9\u5176\u4ED6 CPU \u53D1 IPI \u5237 TLB\uFF0C\u5F00\u9500\u5F88\u5927**\u3002\u5982\u679C\u80FD\u8BA9\u6240\u6709 CPU \u4E0A\u8FD9\u4E2A\u8FDB\u7A0B\u7528\u540C\u4E00\u4E2A PCID\uFF0C\u518D\u914D\u5408 INVLPGB \u8FD9\u6837\u7684\u786C\u4EF6\u5E7F\u64AD\u5931\u6548\u6307\u4EE4\uFF0C\u5C31\u53EF\u4EE5\u7701\u6389 IPI\u3002\\n\\n\u4F46 x86_64 \u7684 PCID \u6570\u91CF\u6709\u9650\uFF084096\uFF0CPTI \u4E0B\u66F4\u5C11\uFF09\uFF0C\u4E0D\u53EF\u80FD\u7ED9\u6BCF\u4E2A\u8FDB\u7A0B\u90FD\u53D1\u4E00\u4E2A\u5168\u5C40 ASID\u3002\u6240\u4EE5\u5185\u6838\u91C7\u53D6**\u6E10\u8FDB\u5F0F\u8FC1\u79FB**\uFF1A\u5148\u7528 Local ASID\uFF0C\u7B49\u53D1\u73B0\u67D0\u4E2A\u8FDB\u7A0B\u540C\u65F6\u5728\u5F88\u591A CPU \u4E0A\u6D3B\u8DC3\uFF0C\u518D\u7ED9\u5B83\u5206\u914D Global ASID\u3002\\n\\n![Global ASID \u7684\u6E10\u8FDB\u5F0F\u8FC1\u79FB](./global-asid-migration.drawio.svg)\\n\\n### \u4EC0\u4E48\u65F6\u5019\u8FC1\u79FB\uFF1F\\n\\n`flush_tlb_mm_range()` \u5728\u8D70 IPI \u8DEF\u5F84\u65F6\uFF0C\u4F1A\u8C03\u7528 `consider_global_asid(mm)`\uFF1A\\n\\n```c\\nstatic void consider_global_asid(struct mm_struct *mm)\\n{\\n    if (!cpu_feature_enabled(X86_FEATURE_INVLPGB))\\n        return;\\n\\n    /* \u6BCF\u9694\u4E00\u6BB5\u65F6\u95F4\u68C0\u67E5\u4E00\u6B21\uFF0C\u907F\u514D\u6BCF\u6B21 flush \u90FD\u67E5 */\\n    if ((current->pid & 0x1f) != (jiffies & 0x1f))\\n        return;\\n\\n    /*\\n     * \u5982\u679C\u8FDB\u7A0B\u540C\u65F6\u5728 4 \u4E2A\u6216\u66F4\u591A CPU \u4E0A\u6D3B\u8DC3\uFF0C\\n     * \u5C31\u7ED9\u5B83\u5206\u914D Global ASID\u3002\\n     */\\n    if (mm_active_cpus_exceeds(mm, 3))\\n        use_global_asid(mm);\\n}\\n```\\n\\n\u5224\u65AD\u6807\u51C6\u662F `mm_active_cpus_exceeds(mm, 3)`\uFF1A\\n\\n```c\\nstatic bool mm_active_cpus_exceeds(struct mm_struct *mm, int threshold)\\n{\\n    int count = 0;\\n    int cpu;\\n\\n    /* \u5FEB\u901F\u8DEF\u5F84\uFF1Amm_cpumask \u91CC\u7684 CPU \u6570\u4E0D\u8D85\u8FC7\u9608\u503C\uFF0C\u76F4\u63A5\u8FD4\u56DE */\\n    if (cpumask_weight(mm_cpumask(mm)) <= threshold)\\n        return false;\\n\\n    /* \u6162\u901F\u8DEF\u5F84\uFF1A\u786E\u8BA4\u8FD9\u4E9B CPU \u771F\u7684\u5728\u8DD1\u8FD9\u4E2A\u8FDB\u7A0B\uFF0C\u800C\u4E0D\u662F lazy */\\n    for_each_cpu(cpu, mm_cpumask(mm)) {\\n        if (per_cpu(cpu_tlbstate.loaded_mm, cpu) != mm)\\n            continue;\\n        if (per_cpu(cpu_tlbstate_shared.is_lazy, cpu))\\n            continue;\\n        if (++count > threshold)\\n            return true;\\n    }\\n    return false;\\n}\\n```\\n\\n### \u5206\u914D Global ASID\\n\\n```c\\nstatic void use_global_asid(struct mm_struct *mm)\\n{\\n    u16 asid;\\n\\n    guard(raw_spinlock_irqsave)(&global_asid_lock);\\n\\n    /* \u5DF2\u7ECF\u6709 Global ASID \u4E86 */\\n    if (mm_global_asid(mm))\\n        return;\\n\\n    /* Global ASID \u6C60\u5DF2\u7ECF\u7A7A\u4E86 */\\n    if (!global_asid_available) {\\n        VM_WARN_ONCE(1, \\"Ran out of global ASIDs\\\\n\\");\\n        return;\\n    }\\n\\n    asid = allocate_global_asid();\\n    if (!asid)\\n        return;\\n\\n    mm_assign_global_asid(mm, asid);\\n}\\n```\\n\\n`allocate_global_asid()` \u4ECE `TLB_NR_DYN_ASIDS` \u5F80\u4E0A\u5206\u914D\u3002\u5F53\u5FEB\u7528\u5B8C\u65F6\uFF0C\u4F1A\u8C03\u7528 `reset_global_asid_space()`\uFF0C\u5148\u7528 `invlpgb_flush_all_nonglobals()` \u5237\u6389\u6240\u6709 Global ASID \u6761\u76EE\uFF0C\u518D\u628A\u5DF2\u91CA\u653E\u7684 Global ASID \u56DE\u6536\u590D\u7528\u3002\\n\\n`mm_assign_global_asid()` \u505A\u4E86\u4EF6\u5F88\u5173\u952E\u7684\u4E8B\uFF1A\\n\\n```c\\nstatic inline void mm_assign_global_asid(struct mm_struct *mm, u16 asid)\\n{\\n    /*\\n     * flush_tlb_mm_range() -> broadcast_tlb_flush() ->\\n     * finish_asid_transition() \u5FC5\u987B\u80FD\u5728\u770B\u5230 global_asid \u4E4B\u540E\\n     * \u7ACB\u523B\u770B\u5230 asid_transition = true\u3002\\n     */\\n    mm->context.asid_transition = true;\\n    smp_store_release(&mm->context.global_asid, asid);\\n}\\n```\\n\\n\u5148\u5199 `asid_transition = true`\uFF0C\u518D\u7528 release store \u5199 `global_asid`\u3002\u8FD9\u6837\u4EFB\u4F55 CPU \u770B\u5230 `global_asid` \u975E\u96F6\u65F6\uFF0C\u4E00\u5B9A\u4E5F\u80FD\u770B\u5230 `asid_transition` \u4E3A\u771F\u3002\\n\\n### \u8FC7\u6E21\u671F\u7684\u540C\u6B65\uFF1Afinish_asid_transition\\n\\n\u8FC1\u79FB\u4E0D\u662F\u4E00\u77AC\u95F4\u5B8C\u6210\u7684\u3002\u5206\u914D Global ASID \u65F6\uFF0C\u5176\u4ED6 CPU \u53EF\u80FD\u8FD8\u5728\u7528\u65E7\u7684 Local ASID \u8DD1\u8FD9\u4E2A\u8FDB\u7A0B\u3002\u5FC5\u987B\u7B49\u6240\u6709 CPU \u90FD\u5207\u5230 Global ASID \u4E4B\u540E\uFF0C\u624D\u80FD\u8BA4\u4E3A\u8FC1\u79FB\u5B8C\u6210\u3002\\n\\n\u8FD9\u4E2A\u5DE5\u4F5C\u7531 `finish_asid_transition()` \u5B8C\u6210\u3002\u5B83\u5728 `broadcast_tlb_flush()` \u8C03\u7528 INVLPGB \u4E4B\u540E\u6267\u884C\uFF1A\\n\\n```c\\nstatic void finish_asid_transition(struct flush_tlb_info *info)\\n{\\n    struct mm_struct *mm = info->mm;\\n    int bc_asid = mm_global_asid(mm);\\n    int cpu;\\n\\n    if (!mm_in_asid_transition(mm))\\n        return;\\n\\n    for_each_cpu(cpu, mm_cpumask(mm)) {\\n        /*\\n         * \u5982\u679C\u8FDC\u7A0B CPU \u6B63\u5728 context switch\uFF0C\u7B49\u5B83\u5B8C\u6210\uFF0C\\n         * \u9632\u6B62\u5B83\u7528\u65E7\u7684 Local ASID \u5207\u5230\u76EE\u6807 mm\u3002\\n         */\\n        while (READ_ONCE(per_cpu(cpu_tlbstate.loaded_mm, cpu)) == LOADED_MM_SWITCHING)\\n            cpu_relax();\\n\\n        if (READ_ONCE(per_cpu(cpu_tlbstate.loaded_mm, cpu)) != mm)\\n            continue;\\n\\n        /*\\n         * \u53EA\u8981\u6709\u4EFB\u4F55\u4E00\u4E2A CPU \u8FD8\u6CA1\u5207\u5230 Global ASID\uFF0C\\n         * \u5C31\u53D1\u4E00\u6B21 TLB flush IPI\u3002IPI \u5904\u7406\u51FD\u6570\u91CC\u4F1A\u68C0\u67E5\\n         * mm_needs_global_asid() \u5E76\u91CD\u65B0\u52A0\u8F7D CR3\u3002\\n         */\\n        if (READ_ONCE(per_cpu(cpu_tlbstate.loaded_mm_asid, cpu)) != bc_asid) {\\n            flush_tlb_multi(mm_cpumask(info->mm), info);\\n            return;\\n        }\\n    }\\n\\n    /* \u6240\u6709\u8DD1\u8FD9\u4E2A\u8FDB\u7A0B\u7684 CPU \u90FD\u5DF2\u7ECF\u7528 Global ASID \u4E86 */\\n    mm_clear_asid_transition(mm);\\n}\\n```\\n\\n\u5728\u8FC7\u6E21\u671F\uFF0C`native_flush_tlb_multi()` \u4F1A\u5F3A\u5236\u7ED9 `mm_cpumask` \u91CC\u7684**\u6240\u6709 CPU** \u53D1 IPI\uFF08\u5305\u62EC lazy \u6A21\u5F0F\u7684 CPU\uFF09\uFF0C\u786E\u4FDD\u5B83\u4EEC\u4E0D\u4F1A\u7EE7\u7EED\u6301\u6709\u65E7\u7684 Local ASID \u6761\u76EE\uFF1A\\n\\n```c\\nif (info->freed_tables || mm_in_asid_transition(info->mm))\\n    on_each_cpu_mask(cpumask, flush_tlb_func, (void *)info, true);\\n```\\n\\n### \u8FC1\u79FB\u5B8C\u6210\u540E\u7684\u6536\u76CA\\n\\n\u4E00\u65E6 `asid_transition` \u88AB\u6E05\u6389\uFF0C\u8FD9\u4E2A mm \u5728\u6240\u6709 CPU \u4E0A\u5C31\u90FD\u7528\u540C\u4E00\u4E2A PCID \u4E86\u3002\u4EE5\u540E `flush_tlb_mm_range()` \u4F1A\u8D70 `broadcast_tlb_flush()`\uFF1A\\n\\n```c\\nstatic void broadcast_tlb_flush(struct flush_tlb_info *info)\\n{\\n    ...\\n    if (info->end == TLB_FLUSH_ALL) {\\n        invlpgb_flush_single_pcid_nosync(kern_pcid(asid));\\n        if (cpu_feature_enabled(X86_FEATURE_PTI))\\n            invlpgb_flush_single_pcid_nosync(user_pcid(asid));\\n    } else {\\n        /* \u8303\u56F4\u5931\u6548 */\\n        ...\\n        invlpgb_flush_user_nr_nosync(kern_pcid(asid), addr, nr, pmd);\\n        ...\\n    }\\n\\n    finish_asid_transition(info);\\n\\n    /* \u7B49\u5F85 INVLPGB \u5E7F\u64AD\u5B8C\u6210 */\\n    __tlbsync();\\n}\\n```\\n\\n\u8FD9\u91CC\u7528 `invlpgb_flush_*_nosync()` \u53D1\u8D77\u786C\u4EF6\u5E7F\u64AD\uFF0C\u518D\u7528 `__tlbsync()` \u7B49\u5F85\u5B8C\u6210\u3002\u4E0D\u9700\u8981\u7ED9\u6BCF\u4E2A CPU \u53D1 IPI\uFF0C\u4E5F\u4E0D\u9700\u8981\u7B49\u5F85\u6BCF\u4E2A CPU \u6267\u884C `flush_tlb_func()`\u3002\u5BF9\u4E8E\u5728\u5927\u91CF CPU \u4E0A\u591A\u7EBF\u7A0B\u8FD0\u884C\u7684\u8FDB\u7A0B\uFF0C\u8FD9\u90E8\u5206\u5F00\u9500\u80FD\u663E\u8457\u964D\u4F4E\u3002\\n\\n### \u8FC1\u79FB\u52A8\u4F5C\u5728\u4E0A\u4E0B\u6587\u5207\u6362\u91CC\u7684\u4F53\u73B0\\n\\n\u5206\u914D Global ASID \u540E\uFF0C\u5F53\u524D CPU \u53EF\u80FD\u4E0B\u4E00\u6B21 `switch_mm_irqs_off()` \u8FDB\u6765\u65F6\u4ECD\u7136\u7528\u7740\u65E7\u7684 Local ASID\u3002`prev == next` \u5FEB\u8DEF\u5F84\u91CC\u4F1A\u68C0\u67E5\uFF1A\\n\\n```c\\nif (mm_needs_global_asid(next, prev_asid)) {\\n    next_tlb_gen = atomic64_read(&next->context.tlb_gen);\\n    ns = choose_new_asid(next, next_tlb_gen);\\n    goto reload_tlb;\\n}\\n```\\n\\n`choose_new_asid()` \u53D1\u73B0 `next->context.global_asid` \u5DF2\u7ECF\u5206\u914D\u597D\uFF0C\u5C31\u76F4\u63A5\u8FD4\u56DE Global ASID\uFF0C\u5E76\u4E14 `need_flush = false`\uFF1A\\n\\n```c\\nif (cpu_feature_enabled(X86_FEATURE_INVLPGB)) {\\n    u16 global_asid = mm_global_asid(next);\\n\\n    if (global_asid) {\\n        ns.asid = global_asid;\\n        ns.need_flush = 0;\\n        return ns;\\n    }\\n}\\n```\\n\\n\u7136\u540E `load_new_mm_cr3(..., false)` \u4E0D\u5E26 flush \u5730\u91CD\u5199 CR3\uFF0C\u628A PCID \u6362\u6210 Global ASID\u3002\u4E4B\u540E\u8FD9\u4E2A CPU \u4E0A\u7684 TLB \u6761\u76EE\u5C31\u548C\u5176\u4ED6 CPU \u7528\u540C\u4E00\u4E2A PCID \u4E86\u3002\\n\\n### Global ASID \u7684\u91CA\u653E\\n\\n\u8FDB\u7A0B\u9000\u51FA\u6216 exec \u65F6\uFF0C`destroy_context()` \u4F1A\u8C03\u7528 `mm_free_global_asid()`\u3002\u88AB\u91CA\u653E\u7684 Global ASID \u4E0D\u4F1A\u7ACB\u5373\u653E\u56DE\u53EF\u7528\u6C60\uFF0C\u800C\u662F\u5148\u6807\u8BB0\u5230 `global_asid_freed` \u4F4D\u56FE\u91CC\uFF0C\u7B49\u5230 `reset_global_asid_space()` \u65F6\u7EDF\u4E00\u7528 INVLPGB \u5237\u5B8C\u518D\u56DE\u6536\u3002\u8FD9\u6837\u907F\u514D\u4E86\u4E00\u4E2A CPU \u8FD8\u5728\u7528\u65E7 PCID \u65F6\u53E6\u4E00\u4E2A CPU \u628A\u540C\u4E00\u4E2A Global ASID \u5206\u914D\u51FA\u53BB\u3002\\n\\n## \u7ED3\u8BED\\n\\n`switch_mm` \u770B\u8D77\u6765\u53EA\u662F\u5199\u4E2A CR3\uFF0C\u4F46\u91CC\u9762\u8981\u5904\u7406\u7684\u4E8B\u60C5\u5F88\u591A\uFF1A\\n\\n- \u5229\u7528 PCID \u505A TLB \u7F13\u5B58\u590D\u7528\uFF1B\\n- \u7528 `tlb_gen` \u5224\u65AD\u7F13\u5B58\u662F\u5426\u8FC7\u671F\uFF1B\\n- \u5173\u4E2D\u65AD\u4FDD\u8BC1\u5207\u6362\u7A97\u53E3\u671F\u7684\u539F\u5B50\u6027\uFF1B\\n- \u5BF9\u5185\u6838\u7EBF\u7A0B\u505A Lazy TLB \u4F18\u5316\uFF1B\\n- \u5BF9\u591A\u7EBF\u7A0B\u5927\u8FDB\u7A0B\u6E10\u8FDB\u5F0F\u8FC1\u79FB\u5230 Global ASID\uFF0C\u914D\u5408\u786C\u4EF6\u5E7F\u64AD\u5931\u6548\u7701\u6389 IPI\u3002\\n\\n\u7406\u89E3\u8FD9\u4E9B\u7EC6\u8282\u4E4B\u540E\uFF0C\u518D\u770B `arch/x86/mm/tlb.c` \u91CC\u7684\u4EE3\u7801\u5C31\u4F1A\u89C9\u5F97\u8109\u7EDC\u6E05\u6670\u5F88\u591A\u3002"},{"id":"multirelational_graph_attention_networks_paper","metadata":{"permalink":"/multirelational_graph_attention_networks_paper","source":"@site/blog/2022-11-22-multirelational_graph_attention_networks_paper/index.mdx","title":"MS-GAT\uFF1A\u7528\u591A\u5173\u7CFB\u56FE\u6CE8\u610F\u529B\u7F51\u7EDC\u5B66\u4E60\u591A\u5C42\u9762\u4EA4\u901A\u8026\u5408","description":"Banner","date":"2022-11-22T00:00:00.000Z","tags":[{"inline":false,"label":"\u6DF1\u5EA6\u5B66\u4E60","permalink":"/tags/dl","description":"\u4E00\u4E9B\u6DF1\u5EA6\u5B66\u4E60\u76F8\u5173\u7684\u6587\u7AE0"},{"inline":false,"label":"\u56FE\u795E\u7ECF\u7F51\u7EDC","permalink":"/tags/gnn","description":"\u4E00\u4E9B\u56FE\u795E\u7ECF\u7F51\u7EDC\u76F8\u5173\u7684\u6587\u7AE0"},{"inline":false,"label":"\u8BBA\u6587","permalink":"/tags/paper","description":"\u4E00\u4E9B\u8BBA\u6587\u76F8\u5173\u7684\u6587\u7AE0"}],"readingTime":7.99,"hasTruncateMarker":true,"authors":[{"name":"Kun Luo","title":"Software Engineer","url":"https://github.com/luokn","page":{"permalink":"/authors/luokun"},"socials":{"github":"https://github.com/luokn","zhihu":"https://www.zhihu.com/people/luokn","email":"mailto:luokun485@gmail.com"},"imageURL":"/img/avatar.jpg","key":"luokun"}],"frontMatter":{"slug":"multirelational_graph_attention_networks_paper","title":"MS-GAT\uFF1A\u7528\u591A\u5173\u7CFB\u56FE\u6CE8\u610F\u529B\u7F51\u7EDC\u5B66\u4E60\u591A\u5C42\u9762\u4EA4\u901A\u8026\u5408","authors":"luokun","tags":["dl","gnn","paper"]},"unlisted":false,"prevItem":{"title":"\u5185\u6838\u6742\u8C08\uFF08\u4E00\uFF09\uFF1ALinux \u91CC\u662F\u600E\u4E48\u5207\u6362\u5730\u5740\u7A7A\u95F4\u7684\uFF1F","permalink":"/linux-switch-mm"},"nextItem":{"title":"\u4F7F\u7528\u6838\u51FD\u6570\u7684\u6CE8\u610F\u529B\u673A\u5236","permalink":"/kernel-function-of-attention-mechanism"}},"content":"![Banner](./framework.png \\"Banner\\")\\n\\n> \u672C\u6587\u4ECB\u7ECD\u6211\u4EEC\u53D1\u8868\u5728 *IEEE Transactions on Intelligent Transportation Systems* \u4E0A\u7684\u5DE5\u4F5C\uFF1A\\n> **Learning Multiaspect Traffic Couplings by Multirelational Graph Attention Networks for Traffic Prediction**\u3002\\n> \\n> - **\u8BBA\u6587\u94FE\u63A5**\uFF1A[![IEEE Xplore](https://img.shields.io/badge/IEEE%20Xplore-9780244-blue)](https://ieeexplore.ieee.org/document/9780244)\\n> - **\u5F15\u7528\u6B21\u6570**\uFF1ACited by 67\uFF08\u622A\u81F3 2025-05\uFF0CIEEE Xplore \u6570\u636E\uFF09\\n> - **\u5F00\u6E90\u4EE3\u7801**\uFF1A[![GitHub](https://img.shields.io/badge/GitHub-luokn%2Fms--gat-181717?logo=github)](https://github.com/luokn/ms-gat)\\n\\n{/* truncate */}\\n\\n## 1. \u80CC\u666F\uFF1A\u4EA4\u901A\u9884\u6D4B\u96BE\u5728\u54EA\u91CC\uFF1F\\n\\n\u5B9E\u65F6\u51C6\u786E\u7684\u4EA4\u901A\u9884\u6D4B\u662F\u667A\u80FD\u4EA4\u901A\u7CFB\u7EDF\uFF08ITS\uFF09\u7684\u6838\u5FC3\u4EFB\u52A1\u4E4B\u4E00\uFF0C\u5BF9\u52A8\u6001\u8DEF\u5F84\u89C4\u5212\u3001\u4FE1\u53F7\u63A7\u5236\u548C\u51FA\u884C\u5F15\u5BFC\u90FD\u6709\u91CD\u8981\u4EF7\u503C\u3002\u7136\u800C\uFF0C\u771F\u5B9E\u9053\u8DEF\u7F51\u7EDC\u4E2D\u7684\u4EA4\u901A\u72B6\u51B5\u53D7\u5230\u591A\u79CD\u590D\u6742\u56E0\u7D20\u7684\u5171\u540C\u5F71\u54CD\uFF1A\\n\\n- **\u65F6\u95F4\u7EF4\u5EA6**\uFF1A\u540C\u4E00\u68C0\u6D4B\u70B9\u5728\u4E0D\u540C\u65F6\u523B\u7684\u6D41\u91CF\u3001\u901F\u5EA6\u3001\u5360\u6709\u7387\u5B58\u5728\u5468\u671F\u6027\u548C\u8D8B\u52BF\u6027\u4F9D\u8D56\uFF1B\\n- **\u7A7A\u95F4\u7EF4\u5EA6**\uFF1A\u76F8\u90BB\u8DEF\u53E3\u3001\u4E0A\u4E0B\u6E38\u8DEF\u6BB5\u7684\u4EA4\u901A\u72B6\u6001\u4F1A\u76F8\u4E92\u4F20\u64AD\uFF1B\\n- **\u591A\u901A\u9053\u8026\u5408**\uFF1A\u540C\u4E00\u4E2A\u8282\u70B9\u5F80\u5F80\u90E8\u7F72\u4E86\u591A\u79CD\u4F20\u611F\u5668\uFF08\u6D41\u91CF\u3001\u901F\u5EA6\u3001\u5BC6\u5EA6\u7B49\uFF09\uFF0C\u8FD9\u4E9B\u4FE1\u53F7\u5728\u73B0\u5B9E\u4E2D\u5E76\u975E\u72EC\u7ACB\uFF0C\u800C\u662F\u5F7C\u6B64\u8026\u5408\u3001\u76F8\u4E92\u5F71\u54CD\u3002\\n\\n\u4F20\u7EDF\u65B9\u6CD5\u5982 ARIMA\u3001SVR\u3001VAR \u7B49\u53EA\u80FD\u5EFA\u6A21\u7B80\u5355\u7684\u65F6\u5E8F\u4F9D\u8D56\uFF1BCNN \u548C RNN \u5206\u522B\u64C5\u957F\u7A7A\u95F4\u6216\u65F6\u95F4\u7279\u5F81\uFF0C\u4F46\u96BE\u4EE5\u540C\u65F6\u5904\u7406\u4E24\u8005\u7684\u4EA4\u4E92\u3002\u8FD1\u5E74\u6765\uFF0C\u56FE\u795E\u7ECF\u7F51\u7EDC\uFF08GNN\uFF09\u5C06\u9053\u8DEF\u7F51\u7EDC\u5EFA\u6A21\u4E3A\u56FE\uFF0C\u5728\u4EA4\u901A\u9884\u6D4B\u4E0A\u53D6\u5F97\u4E86\u663E\u8457\u8FDB\u5C55\uFF0C\u4F8B\u5982 STGCN\u3001DCRNN\u3001Graph WaveNet\u3001AGCRN \u7B49\u65B9\u6CD5\u90FD\u53D6\u5F97\u4E86\u5F88\u597D\u7684\u6548\u679C\u3002\\n\\n\u4F46\u8FD9\u4E9B\u65B9\u6CD5\u5927\u591A\u53EA\u5173\u6CE8**\u65F6\u7A7A\u5173\u7CFB**\uFF0C\u800C\u5FFD\u7565\u4E86\u4EA4\u901A\u4FE1\u53F7\u5728\u4E0D\u540C\u901A\u9053\u4E4B\u95F4\u7684\u8026\u5408\u5173\u7CFB\u3002\u6211\u4EEC\u63D0\u51FA\u5C06\u4EA4\u901A\u7CFB\u7EDF\u770B\u4F5C\u4E00\u4E2A**\u8026\u5408\u4EA4\u901A\u7F51\u7EDC\uFF08Coupled Traffic Network, CTN\uFF09**\uFF0C\u663E\u5F0F\u5EFA\u6A21\u591A\u5C42\u9762\u4EA4\u901A\u4FE1\u53F7\u7684\u8026\u5408\u5173\u7CFB\u3002\\n\\n## 2. \u95EE\u9898\u5B9A\u4E49\uFF1A\u8026\u5408\u4EA4\u901A\u7F51\u7EDC\\n\\n\u6211\u4EEC\u5C06\u9053\u8DEF\u7F51\u7EDC\u5EFA\u6A21\u4E3A\u4E00\u4E2A\u6709\u5411\u56FE $G=(V, E, A)$\uFF0C\u5176\u4E2D $V$ \u662F\u4EA4\u901A\u8282\u70B9\uFF08\u5982\u68C0\u6D4B\u5668\u4F4D\u7F6E\uFF09\uFF0C$E$ \u662F\u8FB9\uFF0C$A \\\\in \\\\mathbb{R}^{N \\\\times N}$ \u662F\u90BB\u63A5\u77E9\u9635\u3002\\n\\n\u6BCF\u4E2A\u8282\u70B9\u5728\u540C\u4E00\u65F6\u523B\u4F1A\u89C2\u6D4B\u5230\u591A\u79CD\u4EA4\u901A\u4FE1\u53F7\uFF08\u6D41\u91CF\u3001\u901F\u5EA6\u3001\u5360\u6709\u7387\u7B49\uFF09\uFF0C\u6211\u4EEC\u628A\u6BCF\u4E00\u79CD\u4FE1\u53F7\u770B\u4F5C\u4E00\u4E2A**\u901A\u9053\uFF08channel\uFF09**\u3002\u4E8E\u662F\uFF0C\u4EA4\u901A\u6761\u4EF6 $X$ \u53EF\u4EE5\u4ECE\u4E09\u4E2A\u7EF4\u5EA6\u7406\u89E3\uFF1A\\n\\n- **\u901A\u9053\u7EF4\u5EA6\uFF08Channel\uFF09**\uFF1A\u540C\u4E00\u8282\u70B9\u4E0D\u540C\u4FE1\u53F7\u4E4B\u95F4\u7684\u76F8\u4E92\u5F71\u54CD\uFF0C\u6784\u6210\u901A\u9053\u5173\u7CFB\uFF1B\\n- **\u65F6\u95F4\u7EF4\u5EA6\uFF08Temporal\uFF09**\uFF1A\u540C\u4E00\u8282\u70B9\u540C\u4E00\u4FE1\u53F7\u5728\u4E0D\u540C\u65F6\u523B\u7684\u6F14\u53D8\uFF0C\u6784\u6210\u65F6\u95F4\u76F8\u5173\u6027\uFF1B\\n- **\u7A7A\u95F4\u7EF4\u5EA6\uFF08Spatial\uFF09**\uFF1A\u540C\u4E00\u65F6\u523B\u4E0D\u540C\u8282\u70B9\u4E4B\u95F4\u7684\u4EA4\u901A\u72B6\u6001\u4F20\u64AD\uFF0C\u6784\u6210\u7A7A\u95F4\u76F8\u5173\u6027\u3002\\n\\n![\u5EFA\u6A21\u6846\u67B6](./core.png \\"\u8026\u5408\u4EA4\u901A\u7F51\u7EDC\u5EFA\u6A21\u6846\u67B6\\")\\n\\n<center>\u56FE 1\uFF1A\u8026\u5408\u4EA4\u901A\u7F51\u7EDC\u4E2D\u7684\u591A\u5C42\u9762\u4EA4\u901A\u4FE1\u53F7\u8026\u5408\u5173\u7CFB</center>\\n\\n\u5F62\u5F0F\u4E0A\uFF0C\u4EFB\u610F\u8282\u70B9 $v$ \u5728\u65F6\u523B $t$ \u7684\u7B2C $l$ \u4E2A\u901A\u9053\u53EF\u4EE5\u8868\u793A\u4E3A $X_v^t(l)$\u3002\u4EA4\u901A\u9884\u6D4B\u4EFB\u52A1\u5373\u5B66\u4E60\u4E00\u4E2A\u6620\u5C04\u51FD\u6570\uFF1A\\n\\n$$\\n[X^{t_p+1}, \\\\dots, X^{t_p+t_q}] = f_G(X^1, \\\\dots, X^{t_p}; \\\\theta)\\n$$\\n\\n\u5176\u4E2D $t_p$ \u662F\u5386\u53F2\u65F6\u95F4\u6B65\uFF0C$t_q$ \u662F\u672A\u6765\u9884\u6D4B\u6B65\uFF0C$\\\\theta$ \u662F\u6A21\u578B\u53C2\u6570\u3002\\n\\n## 3. MS-GAT \u6A21\u578B\u67B6\u6784\\n\\n\u9488\u5BF9\u4E0A\u8FF0\u95EE\u9898\uFF0C\u6211\u4EEC\u63D0\u51FA\u4E86 **Multi-relational Synchronous Graph Attention Networks\uFF08MS-GAT\uFF09**\u3002\u6A21\u578B\u7684\u6574\u4F53\u8BBE\u8BA1\u5982\u4E0B\u56FE\u6240\u793A\uFF1A\\n\\n![MS-GAT \u6846\u67B6](./framework.png \\"MS-GAT \u6574\u4F53\u6846\u67B6\\")\\n\\n<center>\u56FE 2\uFF1AMS-GAT \u6574\u4F53\u6846\u67B6\u3002\u5DE6\u4FA7\u4E3A\u591A\u7EC4\u4EF6\u65F6\u95F4\u95E8\u63A7\u878D\u5408\u7ED3\u6784\uFF0C\u53F3\u4FA7\u4E3A\u6838\u5FC3\u6A21\u5757 MEAM\u3002</center>\\n\\n### 3.1 \u591A\u7EC4\u4EF6\u65F6\u95F4\u95E8\u63A7\u878D\u5408\\n\\n\u4EA4\u901A\u9884\u6D4B\u672C\u8D28\u4E0A\u662F\u4E00\u4E2A\u5E8F\u5217\u5230\u5E8F\u5217\uFF08seq2seq\uFF09\u7684\u5B66\u4E60\u4EFB\u52A1\u3002\u6211\u4EEC\u53D1\u73B0\uFF1A\\n\\n1. \u4E00\u6B21\u6027\u8F93\u5165\u8FC7\u957F\u7684\u5386\u53F2\u5E8F\u5217\u4E0D\u4E00\u5B9A\u80FD\u63D0\u5347\u9884\u6D4B\u7CBE\u5EA6\uFF0C\u53CD\u800C\u4F1A\u589E\u52A0\u6A21\u578B\u5F00\u9500\uFF1B\\n2. \u4E0D\u540C\u5386\u53F2\u65F6\u6BB5\u5BF9\u672A\u6765\u540C\u4E00\u65F6\u523B\u7684\u5F71\u54CD\u5F3A\u5EA6\u5E76\u4E0D\u76F8\u540C\u3002\\n\\n\u56E0\u6B64\uFF0CMS-GAT \u91C7\u7528**\u591A\u7EC4\u4EF6\uFF08multi-component\uFF09\u7ED3\u6784**\u3002\u6BCF\u4E2A\u9884\u6D4B\u7EC4\u4EF6\uFF08Traffic Prediction Component\uFF0CTPC\uFF09\u53EA\u5904\u7406\u4E00\u6BB5\u8F83\u77ED\u7684\u5386\u53F2\u65F6\u95F4\u5E8F\u5217\uFF0C\u591A\u4E2A TPC \u5206\u522B\u5BF9\u5E94\u4E0D\u540C\u504F\u79FB\u91CF\u7684\u5386\u53F2\u65F6\u6BB5\u3002\u901A\u8FC7\u4E00\u4E2A**\u65F6\u95F4\u5D4C\u5165\u95E8\u63A7\uFF08Time Embedding Gate\uFF09**\uFF0C\u6A21\u578B\u81EA\u9002\u5E94\u5730\u878D\u5408\u5404 TPC \u7684\u8F93\u51FA\uFF1A\\n\\n$$\\n\\\\hat{y} = \\\\sum_{i=1}^{M} g_i \\\\odot f_i(x_i)\\n$$\\n\\n\u5176\u4E2D $g_i = TE(D_i, H_i)$ \u7531\u661F\u671F\u51E0 $D_i$ \u548C\u65F6\u523B $H_i$ \u7F16\u7801\u5F97\u5230\uFF0C$\\\\odot$ \u8868\u793A\u9010\u5143\u7D20\u4E58\u79EF\u3002\u8FD9\u79CD\u8BBE\u8BA1\u65E2\u4FDD\u7559\u4E86\u5404\u65F6\u6BB5\u4FE1\u606F\u7684\u5DEE\u5F02\u6027\uFF0C\u53C8\u901A\u8FC7\u95E8\u63A7\u673A\u5236\u5B9E\u73B0\u4E86\u81EA\u9002\u5E94\u878D\u5408\u3002\\n\\n![\u91C7\u6837\u7A97\u53E3](./sampling.png \\"\u591A\u7EC4\u4EF6\u91C7\u6837\u7A97\u53E3\\")\\n\\n<center>\u56FE 3\uFF1A\u591A\u7EC4\u4EF6\u91C7\u6837\u7A97\u53E3\u5728\u65F6\u95F4\u5E8F\u5217\u4E0A\u7684\u6ED1\u52A8\u65B9\u5F0F</center>\\n\\n### 3.2 \u591A\u7EF4\u81EA\u6CE8\u610F\u529B\u673A\u5236\\n\\n\u4E3A\u4E86\u8BA9\u6A21\u578B\u65B9\u4FBF\u5730\u5904\u7406\u4E09\u7EF4\u6570\u636E\uFF08\u901A\u9053\u3001\u65F6\u95F4\u3001\u7A7A\u95F4\uFF09\uFF0C\u6211\u4EEC\u63D0\u51FA\u4E86\u4E00\u79CD**\u591A\u7EF4\u81EA\u6CE8\u610F\u529B\uFF08Multi-dimensional Self-Attention\uFF09\u673A\u5236**\u3002\u76F8\u6BD4\u4F20\u7EDF\u81EA\u6CE8\u610F\u529B\u53EA\u4F5C\u7528\u4E8E\u5355\u4E00\u7EF4\u5EA6\uFF0C\u6211\u4EEC\u7684\u65B9\u6CD5\u53EF\u4EE5\u590D\u7528\u5230\u4EFB\u610F\u7EF4\u5EA6\u3002\\n\\n\u4EE5\u4E09\u7EF4\u6570\u636E $\\\\{h_{x,y,z}\\\\}$ \u4E3A\u4F8B\uFF0C\u82E5\u5E0C\u671B\u6355\u6349 $x$ \u7EF4\u5EA6\u7684\u76F8\u5173\u6027\uFF0C\u53EF\u5C06\u67E5\u8BE2\u548C\u952E\u8BBE\u7F6E\u4E3A $h_{x,:,:}$\uFF0C\u5E76\u901A\u8FC7\u7EBF\u6027\u53D8\u6362\u5F97\u5230 $Q_{\\\\square}$ \u548C $K_{\\\\square}$\u3002\u6CE8\u610F\u529B\u56FE\u8BA1\u7B97\u4E3A\uFF1A\\n\\n$$\\nA_{\\\\square} = \\\\text{softmax}(Q_{\\\\square} W_{\\\\square} K_{\\\\square}^{\\\\top})\\n$$\\n\\n\u4E3A\u4E86\u907F\u514D\u8282\u70B9\u6570\u6216\u65F6\u95F4\u6B65\u8FC7\u5927\u5BFC\u81F4\u53C2\u6570\u7206\u70B8\uFF0C\u6211\u4EEC\u8FDB\u4E00\u6B65\u5C06 $W_{\\\\square}$ \u5206\u89E3\u4E3A\u4E24\u4E2A\u4F4E\u79E9\u77E9\u9635\u7684\u4E58\u79EF $W_{\\\\square} = E_{\\\\square} E_{\\\\square}^{\\\\top}$\uFF0C\u4ECE\u800C\u663E\u8457\u964D\u4F4E\u53C2\u6570\u91CF\u3002\\n\\n![\u591A\u7EF4\u81EA\u6CE8\u610F\u529B](./multidim_attention.png \\"\u591A\u7EF4\u81EA\u6CE8\u610F\u529B\u8BA1\u7B97\u8FC7\u7A0B\\")\\n\\n<center>\u56FE 4\uFF1A\u591A\u7EF4\u81EA\u6CE8\u610F\u529B\u8BA1\u7B97\u8FC7\u7A0B\u793A\u610F\u56FE</center>\\n\\n### 3.3 MEAM\uFF1A\u591A\u5173\u7CFB\u5D4C\u5165\u5E76\u5217\u6A21\u5757\\n\\nMS-GAT \u7684\u6838\u5FC3\u662F **Multi-relational Embedding Abreast Module\uFF08MEAM\uFF09**\u3002\u6BCF\u4E2A MEAM \u5185\u90E8\u6709\u4E09\u4E2A\u5E76\u5217\u5206\u652F\uFF0C\u5206\u522B\u5B66\u4E60\uFF1A\\n\\n- **\u7A7A\u95F4\u5173\u7CFB\u5D4C\u5165**\uFF1A\u901A\u8FC7 GAttention \u8BA1\u7B97\u8282\u70B9\u95F4\u6CE8\u610F\u529B\u56FE\uFF0C\u518D\u7528 GCN \u805A\u5408\u90BB\u5C45\u4FE1\u606F\uFF1B\\n- **\u65F6\u95F4\u5173\u7CFB\u5D4C\u5165**\uFF1A\u901A\u8FC7 TAttention \u6355\u6349\u65F6\u5E8F\u4F9D\u8D56\uFF0C\u518D\u7528 TCN\uFF08\u65F6\u5E8F\u5377\u79EF\u7F51\u7EDC\uFF09\u5EFA\u6A21\u56E0\u679C\u65F6\u5E8F\u5173\u7CFB\uFF1B\\n- **\u901A\u9053\u5173\u7CFB\u5D4C\u5165**\uFF1A\u901A\u8FC7 CAttention \u5B66\u4E60\u4E0D\u540C\u4EA4\u901A\u4FE1\u53F7\u901A\u9053\u4E4B\u95F4\u7684\u8026\u5408\u5173\u7CFB\u3002\\n\\n\u4E09\u4E2A\u5206\u652F\u7684\u8F93\u51FA\u5728\u5C42\u95F4\u62FC\u63A5\u540E\u9001\u5165\u4E0B\u4E00\u5C42 MEAM\uFF0C\u4E0B\u4E00\u5C42\u7684\u81EA\u6CE8\u610F\u529B\u673A\u5236\u4F1A\u9690\u5F0F\u5730\u5B66\u4E60\u5404\u5173\u7CFB\u5BF9\u9884\u6D4B\u7ED3\u679C\u7684\u76F8\u5BF9\u91CD\u8981\u6027\u3002\u901A\u8FC7\u5806\u53E0\u591A\u4E2A MEAM\uFF0C\u6A21\u578B\u80FD\u591F\u540C\u6B65\u3001\u81EA\u9002\u5E94\u5730\u533A\u5206\u65F6\u7A7A\u5173\u7CFB\u548C\u901A\u9053\u5173\u7CFB\u7684\u8D21\u732E\u3002\\n\\n## 4. \u5B9E\u9A8C\u7ED3\u679C\\n\\n\u6211\u4EEC\u5728\u4E94\u4E2A\u771F\u5B9E\u4EA4\u901A\u6570\u636E\u96C6\u4E0A\u8BC4\u4F30\u4E86 MS-GAT\uFF0C\u5305\u62EC PEMSD3\u3001PEMSD4\u3001PEMSD7\u3001PEMSD8 \u548C PEMS-BAY\u3002\u8FD9\u4E9B\u6570\u636E\u96C6\u5747\u6765\u81EA\u52A0\u5DDE Caltrans PeMS \u7CFB\u7EDF\uFF0C\u65F6\u95F4\u7C92\u5EA6\u4E3A 5 \u5206\u949F\u3002\\n\\n| \u6570\u636E\u96C6 | \u8282\u70B9\u6570 | \u8FB9\u6570 | \u65F6\u95F4\u6B65 | \u901A\u9053\u6570 |\\n| :----- | :----- | :--- | :----- | :----- |\\n| PEMSD3 | 358 | 547 | 26,208 | 1 |\\n| PEMSD4 | 307 | 340 | 16,992 | 3 |\\n| PEMSD7 | 883 | 866 | 28,224 | 1 |\\n| PEMSD8 | 170 | 295 | 17,856 | 3 |\\n| PEMS-BAY | 325 | 8,033 | 52,116 | 3 |\\n\\n\u4E0E DCRNN\u3001STGCN\u3001ASTGCN\u3001Graph WaveNet\u3001STSGCN\u3001AGCRN \u7B49\u516D\u79CD\u4E3B\u6D41\u65B9\u6CD5\u76F8\u6BD4\uFF0CMS-GAT \u5728\u7EDD\u5927\u591A\u6570\u6307\u6807\u4E0A\u53D6\u5F97\u4E86\u6700\u4F18\u6216\u63A5\u8FD1\u6700\u4F18\u7684\u7ED3\u679C\u3002\u4F8B\u5982\uFF0C\u5728 PEMSD3\u3001PEMSD4\u3001PEMSD7\u3001PEMSD8 \u4E0A\uFF0CMS-GAT \u7684 MAE \u5206\u522B\u6BD4\u5F53\u65F6\u6700\u597D\u7684\u65B9\u6CD5\u63D0\u5347\u4E86 7.0%\u30011.4%\u30017.8% \u548C 12.6%\u3002\\n\\n![\u6D88\u878D\u5B9E\u9A8C](./ablation.png \\"\u6D88\u878D\u5B9E\u9A8C\u7ED3\u679C\\")\\n\\n<center>\u56FE 5\uFF1AMS-GAT \u5728\u4E0D\u540C\u8BBE\u7F6E\u4E0B\u7684 MAE \u654F\u611F\u6027\u5206\u6790</center>\\n\\n\u6D88\u878D\u5B9E\u9A8C\u8FDB\u4E00\u6B65\u9A8C\u8BC1\u4E86\u4E09\u4E2A\u5173\u952E\u8BBE\u8BA1\u7684\u6709\u6548\u6027\uFF1A\\n\\n1. **\u591A\u7EC4\u4EF6\u7ED3\u6784**\uFF1A\u9002\u5F53\u589E\u52A0 TPC \u6570\u91CF\u80FD\u63D0\u5347\u9884\u6D4B\u7CBE\u5EA6\uFF0C\u4F46\u5E76\u975E\u8D8A\u591A\u8D8A\u597D\uFF0C\u9700\u6839\u636E\u5177\u4F53\u8DEF\u7F51\u590D\u6742\u5EA6\u8C03\u6574\uFF1B\\n2. **\u65F6\u95F4\u5D4C\u5165\uFF08TE\uFF09**\uFF1A\u5F15\u5165\u65F6\u95F4\u5D4C\u5165\u540E\u6A21\u578B\u6027\u80FD consistently \u63D0\u5347\uFF0C\u8BF4\u660E\u4E0D\u540C\u5386\u53F2\u65F6\u6BB5\u5BF9\u672A\u6765\u9884\u6D4B\u7684\u8D21\u732E\u4E0D\u540C\uFF1B\\n3. **\u901A\u9053\u5173\u7CFB\uFF08CAttention\uFF09**\uFF1A\u53BB\u6389\u901A\u9053\u6CE8\u610F\u529B\u540E\u6027\u80FD\u660E\u663E\u4E0B\u964D\uFF0C\u8BC1\u660E\u4E86\u901A\u9053\u5173\u7CFB\u5728\u4EA4\u901A\u9884\u6D4B\u4E2D\u7684\u91CD\u8981\u6027\u3002\\n\\n### \u6848\u4F8B\u7814\u7A76\\n\\n\u6211\u4EEC\u9009\u53D6\u4E86 PEMSD4 \u4E2D\u7684\u4E24\u4E2A\u8282\u70B9\uFF08Node 0 \u548C Node 200\uFF09\u8FDB\u884C\u53EF\u89C6\u5316\u3002\u7ED3\u679C\u663E\u793A\uFF0CMS-GAT \u7684\u9884\u6D4B\u66F2\u7EBF\u4E0E\u771F\u5B9E\u4EA4\u901A\u6D41\u91CF\u8D8B\u52BF\u66F4\u52A0\u543B\u5408\uFF0C\u5C24\u5176\u662F\u5728 Node 200 \u8FD9\u79CD\u6CE2\u52A8\u76F8\u5BF9\u89C4\u5F8B\u7684\u8282\u70B9\u4E0A\u4F18\u52BF\u660E\u663E\u3002Node 0 \u7531\u4E8E\u5B58\u5728\u9891\u7E41\u7684\u968F\u673A\u4EA4\u901A\u4E8B\u4EF6\uFF08\u5982\u77ED\u65F6\u62E5\u5835-\u758F\u901A\u4EA4\u66FF\uFF09\uFF0C\u9884\u6D4B\u96BE\u5EA6\u66F4\u5927\uFF0C\u4F46 MS-GAT \u4ECD\u8868\u73B0\u51FA\u66F4\u597D\u7684\u9002\u5E94\u6027\u3002\\n\\n![\u6848\u4F8B\u7814\u7A76 1](./case_1.png \\"Node 0 \u4E0E Node 200 \u7684\u6D41\u91CF\u9884\u6D4B\u5BF9\u6BD4\\")\\n\\n<center>\u56FE 6\uFF1ANode 0 \u4E0E Node 200 \u7684\u672A\u6765 24 \u5C0F\u65F6\u6D41\u91CF\u9884\u6D4B\u5BF9\u6BD4</center>\\n\\n![\u6848\u4F8B\u7814\u7A76 2](./case_2.png \\"Node 0 \u7684\u9884\u6D4B\u8BEF\u5DEE\u5BF9\u6BD4\\")\\n\\n<center>\u56FE 7\uFF1ANode 0 \u7684\u9884\u6D4B\u8BEF\u5DEE\u5BF9\u6BD4</center>\\n\\n## 5. \u603B\u7ED3\\n\\nMS-GAT \u7684\u6838\u5FC3\u8D21\u732E\u5728\u4E8E\uFF1A\\n\\n1. **\u9996\u6B21\u5728\u4EA4\u901A\u9884\u6D4B\u4E2D\u663E\u5F0F\u5EFA\u6A21\u901A\u9053\u5173\u7CFB**\uFF0C\u5C06\u4EA4\u901A\u7CFB\u7EDF\u89C6\u4E3A\u901A\u9053\u3001\u65F6\u95F4\u3001\u7A7A\u95F4\u4E09\u7EF4\u8026\u5408\u7684\u590D\u6742\u7F51\u7EDC\uFF1B\\n2. \u63D0\u51FA\u4E86**\u591A\u7EF4\u81EA\u6CE8\u610F\u529B\u673A\u5236**\uFF0C\u4F7F\u81EA\u6CE8\u610F\u529B\u80FD\u591F\u65B9\u4FBF\u5730\u6269\u5C55\u5230\u591A\u7EF4\u6570\u636E\uFF1B\\n3. \u8BBE\u8BA1\u4E86**\u591A\u5173\u7CFB\u5D4C\u5165\u5E76\u5217\u6A21\u5757\uFF08MEAM\uFF09**\uFF0C\u540C\u6B65\u5B66\u4E60\u5E76\u81EA\u9002\u5E94\u878D\u5408\u4E09\u79CD\u5173\u7CFB\u3002\\n\\n\u5728\u4E94\u4E2A\u771F\u5B9E\u6570\u636E\u96C6\u4E0A\u7684\u5B9E\u9A8C\u8868\u660E\uFF0CMS-GAT \u80FD\u591F\u6709\u6548\u6355\u6349\u4EA4\u901A\u4FE1\u53F7\u4E4B\u95F4\u7684\u591A\u5C42\u9762\u8026\u5408\u5173\u7CFB\uFF0C\u5728\u77ED\u65F6\u548C\u957F\u65F6\u9884\u6D4B\u4EFB\u52A1\u4E0A\u90FD\u4F18\u4E8E\u591A\u79CD\u4E3B\u6D41\u57FA\u7EBF\u65B9\u6CD5\u3002\\n\\n\u5982\u679C\u4F60\u5BF9\u5177\u4F53\u5B9E\u73B0\u611F\u5174\u8DA3\uFF0C\u6B22\u8FCE\u67E5\u770B\u5F00\u6E90\u4EE3\u7801\uFF1A\\n\\n[![GitHub](https://img.shields.io/badge/GitHub-luokn%2Fms--gat-181717?logo=github)](https://github.com/luokn/ms-gat)\\n\\n## \u5F15\u7528\u4FE1\u606F\\n\\n```bibtex\\n@ARTICLE{9780244,\\n  author  = {Huang, Jing and Luo, Kun and Cao, Longbing and Wen, Yuanqiao and Zhong, Shuyuan},\\n  journal = {IEEE Transactions on Intelligent Transportation Systems},\\n  title   = {Learning Multiaspect Traffic Couplings by Multirelational Graph Attention Networks for Traffic Prediction},\\n  year    = {2022},\\n  volume  = {23},\\n  number  = {},\\n  pages   = {20681-20695},\\n  doi     = {10.1109/TITS.2022.3173689}\\n}\\n```\\n\\n> **\u8BBA\u6587\u94FE\u63A5**\uFF1Ahttps://ieeexplore.ieee.org/document/9780244\\n>\\n> **Cited by 67**\uFF08IEEE Xplore\uFF0C2025-05\uFF09"},{"id":"kernel-function-of-attention-mechanism","metadata":{"permalink":"/kernel-function-of-attention-mechanism","source":"@site/blog/2022-09-05-kernel-function-of-attention-mechanism.md","title":"\u4F7F\u7528\u6838\u51FD\u6570\u7684\u6CE8\u610F\u529B\u673A\u5236","description":"\u6700\u8FD1\u5728\u7814\u7A76\u5404\u79CD\u5404\u6837\u7684Attention\u673A\u5236\u65F6\uFF0C\u53D1\u73B0Transformer\u7684\u51E0\u79CDAttention\u7684\u8BA1\u7B97\u53EF\u4EE5\u7EDF\u4E00\u63CF\u8FF0\u4E3A\u952E\u503C\u5728\u5185\u79EF\u7A7A\u95F4\u7684\u6620\u5C04\u4EE5\u53CA\u5176\u5185\u79EF\u7A7A\u95F4\u7684\u5185\u79EF\u8FD0\u7B97\uFF0C\u5728\u8DF3\u8131\u51FA\u6B27\u6C0F\u7A7A\u95F4\u7684\u9650\u5236\u540E\uFF0C\u6211\u4EEC\u53EF\u4EE5\u4F7F\u7528\u6838\u51FD\u6570\u6765\u5BF9Attention\u8FDB\u884C\u5EFA\u6A21\u548C\u6269\u5C55\uFF0C\u672C\u6587\u5C06\u8BA8\u8BBA\u8FD9\u4E2A\u95EE\u9898\u3002","date":"2022-09-05T00:00:00.000Z","tags":[{"inline":false,"label":"\u6570\u5B66","permalink":"/tags/math","description":"\u4E00\u4E9B\u6570\u5B66\u76F8\u5173\u7684\u6587\u7AE0"},{"inline":false,"label":"\u6DF1\u5EA6\u5B66\u4E60","permalink":"/tags/dl","description":"\u4E00\u4E9B\u6DF1\u5EA6\u5B66\u4E60\u76F8\u5173\u7684\u6587\u7AE0"}],"readingTime":3.18,"hasTruncateMarker":true,"authors":[{"name":"Kun Luo","title":"Software Engineer","url":"https://github.com/luokn","page":{"permalink":"/authors/luokun"},"socials":{"github":"https://github.com/luokn","zhihu":"https://www.zhihu.com/people/luokn","email":"mailto:luokun485@gmail.com"},"imageURL":"/img/avatar.jpg","key":"luokun"}],"frontMatter":{"slug":"kernel-function-of-attention-mechanism","title":"\u4F7F\u7528\u6838\u51FD\u6570\u7684\u6CE8\u610F\u529B\u673A\u5236","authors":"luokun","tags":["math","dl"]},"unlisted":false,"prevItem":{"title":"MS-GAT\uFF1A\u7528\u591A\u5173\u7CFB\u56FE\u6CE8\u610F\u529B\u7F51\u7EDC\u5B66\u4E60\u591A\u5C42\u9762\u4EA4\u901A\u8026\u5408","permalink":"/multirelational_graph_attention_networks_paper"},"nextItem":{"title":"\u67EF\u897F-\u6BD4\u5185\u516C\u5F0F\u8BC1\u660E","permalink":"/proof-of-cauchy-binet-formula"}},"content":":::tip\\n\u6700\u8FD1\u5728\u7814\u7A76\u5404\u79CD\u5404\u6837\u7684Attention\u673A\u5236\u65F6\uFF0C\u53D1\u73B0**Transformer**\u7684\u51E0\u79CDAttention\u7684\u8BA1\u7B97\u53EF\u4EE5\u7EDF\u4E00\u63CF\u8FF0\u4E3A\u952E\u503C\u5728**\u5185\u79EF\u7A7A\u95F4\u7684\u6620\u5C04**\u4EE5\u53CA\u5176**\u5185\u79EF\u7A7A\u95F4\u7684\u5185\u79EF\u8FD0\u7B97**\uFF0C\u5728\u8DF3\u8131\u51FA\u6B27\u6C0F\u7A7A\u95F4\u7684\u9650\u5236\u540E\uFF0C\u6211\u4EEC\u53EF\u4EE5\u4F7F\u7528**\u6838\u51FD\u6570**\u6765\u5BF9Attention\u8FDB\u884C\u5EFA\u6A21\u548C\u6269\u5C55\uFF0C\u672C\u6587\u5C06\u8BA8\u8BBA\u8FD9\u4E2A\u95EE\u9898\u3002\\n:::\\n\\n{/* truncate */}\\n\\n## Transformer\u4E2D\u7684\u6CE8\u610F\u529B\u662F\u4EC0\u4E48\u6837\u7684\uFF1F\\n\\n**Transformer \u4E2D\u7684\u6CE8\u610F\u529B**\uFF1A$\\\\forall k,q \\\\in \\\\mathbb{R}^{D_k}$, $K=(k_1,k_2,\\\\cdots,k_N)$\uFF0C$Q=(q_1,q_2,\\\\cdots,q_N)$, $a:\\\\mathbb{R}^{D_k} \\\\times \\\\mathbb{R}^{D_k} \\\\to \\\\mathbb{R},k,q \\\\mapsto \\\\alpha$\uFF0C\\n\u4EE4$A=(a_{ij}) \\\\in \\\\mathbb{R}^{N},\\\\alpha_{ij} = a(k_i, q_j)$\uFF0C\u5219\uFF1A\\n\\n$$\\nAttention(K,Q,V) = Softmax(A)V\\n$$\\n\\n$a$\u5E38\u7528\u4EE5\u4E0B\u51E0\u79CD\uFF1A\\n\\n- \u70B9\u79EF\uFF1A$a(k_i, q_j) = k_i q_j$\\n- \u7F29\u653E\u70B9\u79EF\uFF1A$a(k_i, q_j) = \\\\frac{k_i q_j}{\\\\sqrt{D_k}}$\\n- \u53CC\u7EBF\u6027\uFF1A$a(k_i,q_j)=k_i W q_j$\\n- \u62FC\u63A5\uFF1A$a(k_i,q_j)=W[k_i||q_j]$\\n\\n## \u5982\u4F55\u7528\u6838\u51FD\u6570\u6765\u89E3\u91CA\u8FD9\u51E0\u79CD$a$\uFF1F\\n\\n\u4F7F\u7528\u201C**\u6838\u6CE8\u610F\u529B\u673A\u5236**\u201D\u6765\u89E3\u91CA\uFF1A\u6211\u4EEC\u5C06\u70B9\u79EF\u3001\u7F29\u653E\u70B9\u79EF\u3001\u53CC\u7EBF\u6027\u3001\u62FC\u63A5\u53EF\u7EDF\u4E00\u63CF\u8FF0\u4E3A\u952E\u503C\u5728\u5185\u79EF\u7A7A\u95F4\u7684\u6620\u5C04\u4EE5\u53CA\u5176\u5185\u79EF\u7A7A\u95F4\u7684\u5185\u79EF\u8FD0\u7B97\uFF0C\u5373\uFF1A\\n\\n$$\\na(k_i,q_j) = \\\\langle \\\\phi(k_i) , \\\\varphi(q_j) \\\\rangle\\n$$\\n\\n\u5176\u4E2D$\\\\phi,\\\\varphi:\\\\mathbb{R}^{D_k} \\\\to \\\\mathcal{H}$\uFF0C$\\\\mathcal{H}$\u4E3A\u5185\u79EF\u7A7A\u95F4\uFF0C\u5219\u53EF\u4EE4\u6838\u51FD\u6570\u4E3A$\\\\mathcal K = \\\\langle, \\\\rangle$\uFF0C\u5373\uFF1A\\n\\n$$\\n\\\\mathcal K(k_i,q_j) = \\\\langle \\\\phi(k_i) , \\\\varphi(q_j) \\\\rangle\\n$$\\n\\n\u5BF9\u4E8E**\u70B9\u79EF\u6A21\u578B**\uFF0C\u4EE4$\\\\phi=\\\\varphi = \\\\mathop{id}$\uFF0C\u5219\u6709\uFF1A\\n\\n$$\\n\\\\mathcal K(k_i,q_j) = \\\\langle k_i , q_i \\\\rangle= k_i q_j\\n$$\\n\\n\u5BF9\u4E8E**\u7F29\u653E\u70B9\u79EF\u6A21\u578B**\uFF0C\u4EE4$\\\\phi(k_i)=\\\\frac{k_i}{\\\\sqrt{D_k}}, \\\\varphi = id$\uFF0C\u5219\u6709\uFF1A\\n\\n$$\\n\\\\mathcal K(k_i,q_j) = \\\\langle \\\\frac {k_i}{\\\\sqrt{D_k}} , q_i \\\\rangle = \\\\frac{k_iq_j}{\\\\sqrt{D_k}}\\n$$\\n\\n\u5BF9\u4E8E**\u53CC\u7EBF\u6027\u6A21\u578B**\uFF0C\u4EE4$\\\\phi(k_i) = k_i W_1, \\\\varphi(q_i) = W_2q_i,W=W_1W_2$\uFF0C\u5219\u6709\uFF1A\\n\\n$$\\n\\\\mathcal K(k_i,q_j) = \\\\langle k_i W_1 , W_2q_j \\\\rangle = k_i W_1 W_2 q_j = k_i W q_j\\n$$\\n\\n\u5BF9\u4E8E**\u62FC\u63A5\u6A21\u578B**\uFF0C\u53EA\u9700\u8981\u6620\u5C04\u5230\u66F4\u9AD8\u7EF4\u7684\u6B27\u6C0F\u7A7A\u95F4\u5373\u53EF\uFF0C\u4EE4\uFF1A\\n\\n$$\\n\\\\phi((k_i^1,\\\\cdots,k_i^{D_k}))=(u_1 k_i^1, \\\\cdots , u_{D_k}k^{D_k}_i,1,\\\\cdots,1) \\\\in \\\\mathbb{R}^{2 D_k}\\n$$\\n\\n$$\\n\\\\varphi((q_i^1,\\\\cdots,q_i^{D_k}))=(1, \\\\cdots, 1, v_1 q_j^1, \\\\cdots ,v_{D_k}q^{D_k}_j) \\\\in \\\\mathbb{R}^{2 D_k}\\n$$\\n\\n$$\\nW=(u_1,\\\\cdots,u_{D_k},v_1,\\\\cdots,v_{D_k}) \\\\in \\\\mathbb{R}^{2D_k}\\n$$\\n\\n\u5219\u6709\uFF1A\\n\\n$$\\n\\\\begin{aligned}\\n\\\\mathcal{K}(k_i, q_j)\\n&= \\\\langle (u_1 k_i^1, \\\\cdots , u_{D_k}k^{D_k}i,1,\\\\cdots,1) , (1, \\\\cdots, 1, v_1 q_j^1, \\\\cdots ,v{D_k}q^{D_k}_j) \\\\rangle = u_r k_i^{r} + v_s q_j^{s} = W[k_i||q_j]\\n\\\\end{aligned}\\n$$\\n\\n## \u5173\u4E8E\u9AD8\u7EF4\u60C5\u51B5\u548C\u975E\u7EBF\u6027\u6838\u7684\u8BA8\u8BBA\\n\\n**\u9AD8\u7EF4\u60C5\u51B5**\uFF1A\u82E5$k_i, q_j$\u4E3A\u9AD8\u7EF4\u7684\u77E9\u9635\u751A\u81F3\u662F\u5F20\u91CF\uFF0C\u53EF\u4EE5\u5C06\u6838\u51FD\u6570$\\\\mathcal{K}$\u6269\u5C55\u5230\u9AD8\u7EF4\u60C5\u5F62\uFF0C\u5DF2\u4E8C\u7EF4\u5F20\u91CF\u77E9\u9635\u4E3A\u4F8B\uFF0C\u53EF\u4EE5\u5C06\u77E9\u9635\u7684\u5206\u91CF\u5D4C\u5165\u5230\u6B27\u5F0F\u7A7A\u95F4\u6765\u8BA1\u7B97\u5185\u79EF\uFF0C\u5982\uFF1A\\n\\n$$\\n\\\\mathcal{K}(k_i, q_j) = \\\\langle \\\\phi(k_i) , \\\\varphi(q_j) \\\\rangle = k_i^{pq}q_j^{pq}\\n$$\\n\\n\u5373$k_i$\u4E0E$q_j$\u7684\u54C8\u8FBE\u9A6C\u79EF\u7684\u6240\u6709\u5206\u91CF\u7684\u6570\u503C\u548C\u3002\\n\\n**\u975E\u7EBF\u6027\u6838**\uFF1A\u53EF\u4EE5\u770B\u51FA\uFF0C\u7EBF\u6027\u6838\u6CE8\u610F\u529B\u673A\u5236\u90FD\u53EA\u5BF9\u952E\u503C\u5206\u91CF\u8FDB\u884C\u653E\u7F29\u4EE5\u8BA1\u7B97\u5185\u79EF\uFF0C\u672C\u8D28\u4E0A\u63D0\u53D6\u7684\u4ECD\u662F\u7EBF\u6027\u76F8\u5173\u6027\uFF0C\u5BF9\u4E8E\u975E\u7EBF\u6027\u7684\u76F8\u5173\u6027\u5374\u65E0\u80FD\u4E3A\u529B\u3002\u4EE5\u9AD8\u65AF\u6838\u4E3A\u4F8B\uFF0C\u4F7F\u7528\u975E\u7EBF\u6027\u6838\u7684\u6CE8\u610F\u529B\u673A\u5236\u5982\u4E0B\uFF1A\\n\\n$$\\n\\\\mathcal K(k_i,q_j) = exp({-\\\\frac{||k_i - q_j||^2}{2 \\\\sigma^2}})\\n$$\\n\\n## \u5982\u4F55\u4F7F\u7528\u201C\u6838\u6CE8\u610F\u529B\u673A\u5236\u201D\uFF1F\\n\\n\u5C1D\u8BD5\u5C06\u975E\u7EBF\u6027\u6838\uFF08\u6BD4\u5982\u9AD8\u65AF\u6838\uFF09\u5F15\u5165\u6CE8\u610F\u529B\u673A\u5236\u4E2D\u6765\u89E3\u51B3\u4E00\u4E9B\u7279\u6B8A\u7684\u6570\u636E\u4E0A\uFF0C\u4F46\u6548\u679C\u9700\u8981\u8FDB\u4E00\u6B65\u8BC4\u4F30\u3002"},{"id":"proof-of-cauchy-binet-formula","metadata":{"permalink":"/proof-of-cauchy-binet-formula","source":"@site/blog/2021-11-02-proof-of-cauchy-binet-formula.md","title":"\u67EF\u897F-\u6BD4\u5185\u516C\u5F0F\u8BC1\u660E","description":"\u5982\u4F55\u7406\u89E3\u6216\u662F\u8BC1\u660E\u67EF\u897F-\u6BD4\u5185\u516C\u5F0F\uFF1F - \u695A\u5357\u51A5\u7075\u7684\u56DE\u7B54 - \u77E5\u4E4E","date":"2021-11-02T00:00:00.000Z","tags":[{"inline":false,"label":"\u6570\u5B66","permalink":"/tags/math","description":"\u4E00\u4E9B\u6570\u5B66\u76F8\u5173\u7684\u6587\u7AE0"}],"readingTime":5.12,"hasTruncateMarker":true,"authors":[{"name":"Kun Luo","title":"Software Engineer","url":"https://github.com/luokn","page":{"permalink":"/authors/luokun"},"socials":{"github":"https://github.com/luokn","zhihu":"https://www.zhihu.com/people/luokn","email":"mailto:luokun485@gmail.com"},"imageURL":"/img/avatar.jpg","key":"luokun"}],"frontMatter":{"slug":"proof-of-cauchy-binet-formula","title":"\u67EF\u897F-\u6BD4\u5185\u516C\u5F0F\u8BC1\u660E","authors":"luokun","tags":["math"]},"unlisted":false,"prevItem":{"title":"\u4F7F\u7528\u6838\u51FD\u6570\u7684\u6CE8\u610F\u529B\u673A\u5236","permalink":"/kernel-function-of-attention-mechanism"},"nextItem":{"title":"\u7ECF\u5178\u673A\u5668\u5B66\u4E60\u7B97\u6CD5\u7684\u6781\u7B80\u5B9E\u73B0","permalink":"/classic-machine-learning-algorithms"}},"content":"> [\u5982\u4F55\u7406\u89E3\u6216\u662F\u8BC1\u660E\u67EF\u897F-\u6BD4\u5185\u516C\u5F0F\uFF1F - \u695A\u5357\u51A5\u7075\u7684\u56DE\u7B54 - \u77E5\u4E4E](https://www.zhihu.com/question/338686326/answer/943638530)\\n\\n**\u5B9A\u7406\uFF1A** $\\\\forall A \\\\in \\\\mathbb{R}^{m \\\\times n}, \\\\forall B \\\\in \\\\mathbb{R}^{n \\\\times m}$ \uFF0C\u6709:\\n\\n$$\\ndet(AB)=\\n\\\\left\\\\{\\n\\\\begin{aligned}\\n    &0 &,if \\\\quad m > n\\\\\\\\\\n    &detA \\\\cdot detB &,if \\\\quad m = n \\\\\\\\\\n    &\\\\sum \\\\limits_{1 \\\\le i_1 \\\\lt \\\\cdots \\\\lt i_m \\\\le n}\\n    \\\\left |\\n    \\\\begin{array}{ccc}\\n        a^1_{i_1} & \\\\cdots & a^1_{i_m} \\\\\\\\\\n           \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        a^m_{i_1} & \\\\cdots & a^m_{i_m}\\n    \\\\end{array}\\n    \\\\right |\\n    \\\\cdot\\n    \\\\left |\\n    \\\\begin{array}{ccc}\\n        b^{i_1}_{1} & \\\\cdots & b^{i_1}_{m} \\\\\\\\\\n           \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        b^{i_m}_{1} & \\\\cdots & b^{i_m}_{m}\\n    \\\\end{array}\\n    \\\\right |\\n    &,if \\\\quad m < n\\n\\\\end{aligned}\\n\\\\right.\\n$$\\n\\n{/* truncate */}\\n\\n**\u8BC1\u660E:** \u8BBE$f:\\\\mathbb{E}^n \\\\to \\\\mathbb{E}^m$\u4E0E$g:\\\\mathbb{E}^m \\\\to \\\\mathbb{E}^n$\u4E3A\u7EBF\u6027\u6620\u5C04\uFF0C\u5B9A\u4E49\u6620\u5C04\\n$$\\n\\\\bigwedge^p f: \\\\bigwedge^p \\\\mathbb{R}^n \\\\to \\\\bigwedge^p \\\\mathbb{R}^m,\\nu_1 \\\\wedge \\\\cdots\\\\wedge u_p \\\\mapsto f(u_1) \\\\wedge \\\\cdots \\\\wedge f(u_p)\\n$$\\n\\n$$\\n\\\\bigwedge^p g: \\\\bigwedge^p \\\\mathbb{R}^m \\\\to \\\\bigwedge^p \\\\mathbb{R}^n,\\nv_1 \\\\wedge \\\\cdots\\\\wedge v_p \\\\mapsto g(v_1) \\\\wedge \\\\cdots \\\\wedge g(v_p)\\n$$\\n\\n\u6545\u6709\\n\\n$$\\n\\\\begin{aligned}\\n(\\\\bigwedge^p f \\\\circ \\\\bigwedge^p g)(v_1 \\\\wedge \\\\cdots\\\\wedge v_p)\\n&=\\\\bigwedge^k f(g(v_1) \\\\wedge \\\\cdots \\\\wedge g(v_p)) \\\\\\\\\\n&=((f \\\\circ g)(v_1)) \\\\wedge \\\\cdots \\\\wedge ((f \\\\circ g)(v_p)) \\\\\\\\\\n&=(\\\\bigwedge^k (f \\\\circ g))(v_1 \\\\wedge \\\\cdots\\\\wedge v_p)\\n\\\\end{aligned}\\n$$\\n\\n\u4E8E\u662F\\n\\n$$\\n\\\\bigwedge^k f \\\\circ \\\\bigwedge^k g = \\\\bigwedge^k (f \\\\circ g)\\n$$\\n\\n\u4EE4$p=m$\uFF0C\u5219:\\n\\n$$\\n\\\\bigwedge^m f \\\\circ \\\\bigwedge^m g = \\\\bigwedge^m (f \\\\circ g)\\n$$\\n\\n\u5F53$m>n$\u65F6\uFF1A$\\\\bigwedge^m g(v_1 \\\\wedge \\\\cdots \\\\wedge v_m) = g(v_1) \\\\wedge \\\\cdots \\\\wedge g(v_m) \\\\in \\\\bigwedge^m \\\\mathbb{E}^n$\uFF0C\u800C$\\\\mathbb{E}^n$\u4E2D\u7684$m$\u4E2A\u5411\u91CF$\\\\{g(v_1),\\\\cdots,g(v_m)\\\\}$\u5FC5\u5B9A\u662F\u662F\u7EBF\u6027\u76F8\u5173\u7684\uFF0C\u56E0\u6B64\uFF1A$g(v_1) \\\\wedge \\\\cdots \\\\wedge g(v_m) = 0$\uFF0C\u5373\uFF1A\\n\\n$$\\n(\\\\bigwedge^m f \\\\circ \\\\bigwedge^m g)(v_1 \\\\wedge \\\\cdots\\\\wedge v_m)\\n= (\\\\bigwedge^m (f \\\\circ g))(v_1 \\\\wedge \\\\cdots\\\\wedge v_m)\\n= 0\\n$$\\n\\n\u5F53$m \\\\le n$\u65F6\uFF1A\u53D6$\\\\{\\\\delta_i\\\\}_{1 \\\\le i \\\\le n}$\u4E3A$\\\\mathbb{E}^n$\u7684\u57FA\u5E95\uFF0C$\\\\{\\\\omega_i\\\\}_{1 \\\\le i \\\\le m}$\u4E3A $\\\\mathbb{E}^m$ \u7684\u57FA\u5E95\uFF0C\u8BBE$f$\u5728\u6B64\u57FA\u5E95\u4E0B\u7684\u77E9\u9635\u5F62\u5F0F\u4E3A $A = (a^i_j)$\uFF0C$g$\u5728\u6B64\u57FA\u5E95\u4E0B\u7684\u77E9\u9635\u5F62\u5F0F\u4E3A $B=(b^i_j)$\uFF0C\u4E14 $C=AB=(c^i_j)$\uFF0C\u5219\\n\\n$$\\nf(x^k\\\\delta_k)=x^j a^i_j \\\\omega_i\\n$$\\n\\n$$\\ng(x^k\\\\omega_k)=x^j b_j^i \\\\delta_i\\n$$\\n\\n\u6545\u6709\\n\\n$$\\n\\\\begin{aligned}\\n(\\\\bigwedge^m f \\\\circ \\\\bigwedge^m g)(\\\\omega_1 \\\\wedge \\\\cdots \\\\wedge \\\\omega_m)\\n&= \\\\bigwedge^m f\\n\\\\left(g(\\\\omega_1) \\\\wedge \\\\cdots \\\\wedge g(\\\\omega_m)\\\\right) \\\\\\\\\\n&= \\\\bigwedge^m f\\n\\\\left((b_1^{i_1} \\\\delta_{i_1}) \\\\wedge \\\\cdots \\\\wedge (b_m^{i_m} \\\\delta_{i_m})\\\\right) \\\\\\\\\\n&= \\\\bigwedge^m f\\n\\\\left(b_1^{i_1} \\\\cdots b_m^{i_m} \\\\delta_{i_1} \\\\wedge \\\\cdots \\\\wedge \\\\delta_{i_m}\\\\right) \\\\\\\\\\n&=\\n\\\\bigwedge^m f\\n\\\\left(\\n\\\\sum \\\\limits_{1 \\\\le i_i < \\\\cdots < i_m \\\\le n}\\n\\\\left |\\n    \\\\begin{array}{ccc}\\n        b_{1}^{i_1} & \\\\cdots & b_{m}^{i_1} \\\\\\\\\\n        \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        b_{1}^{i_m} & \\\\cdots & b_{m}^{i_m}\\n    \\\\end{array}\\n\\\\right |\\n\\\\delta_{i_1} \\\\wedge \\\\cdots \\\\wedge \\\\delta_{i_m}\\n\\\\right) \\\\\\\\\\n&=\\n\\\\sum \\\\limits_{1 \\\\le i_i < \\\\cdots < i_m \\\\le n}\\n\\\\left |\\n    \\\\begin{array}{ccc}\\n        b_{1}^{i_1} & \\\\cdots & b_{m}^{i_1} \\\\\\\\\\n        \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        b_{1}^{i_m} & \\\\cdots & b_{m}^{i_m}\\n    \\\\end{array}\\n\\\\right |\\n\\\\cdot\\n\\\\bigwedge^m f(\\\\delta_{i_1} \\\\wedge \\\\cdots \\\\wedge \\\\delta_{i_m} )\\n\\\\\\\\\\n\\\\end{aligned}\\n$$\\n\\n\u5176\u4E2D\\n\\n$$\\n\\\\begin{aligned}\\n\\\\bigwedge^m f(\\\\delta_{i_1} \\\\wedge \\\\cdots \\\\wedge \\\\delta_{i_m})\\n&= f(\\\\delta_{i_1}) \\\\wedge \\\\cdots \\\\wedge f(\\\\delta_{i_m}) \\\\\\\\\\n&= (a_{i_1}^{j_1} \\\\omega_{j_1}) \\\\wedge \\\\cdots \\\\wedge (a_{i_m}^{j_m} \\\\omega_{j_m}) \\\\\\\\\\n&= a_{i_1}^{j_1} \\\\cdots a_{i_m}^{j_m} \\\\omega_{j_1} \\\\wedge \\\\cdots \\\\wedge \\\\omega_{j_m} \\\\\\\\\\n&=\\n\\\\left |\\n    \\\\begin{array}{ccc}\\n        a_{i_1}^{1} & \\\\cdots & a_{i_m}^{1} \\\\\\\\\\n           \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        a_{i_1}^{m} & \\\\cdots & a_{i_m}^{m}\\n    \\\\end{array}\\n\\\\right |\\n\\\\omega_{1} \\\\wedge \\\\cdots \\\\wedge \\\\omega_{m}\\n\\\\end{aligned}\\n$$\\n\\n\u6240\u4EE5\\n\\n$$\\n\\\\begin{aligned}\\n(\\\\bigwedge^m f \\\\circ \\\\bigwedge^m g)(\\\\omega_1 \\\\wedge \\\\cdots \\\\wedge \\\\omega_m)\\n&=\\n\\\\sum \\\\limits_{1 \\\\le i_i < \\\\cdots < i_m \\\\le n}\\n\\\\left |\\n    \\\\begin{array}{ccc}\\n        b_{1}^{i_1} & \\\\cdots & b_{m}^{i_1} \\\\\\\\\\n        \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        b_{1}^{i_m} & \\\\cdots & b_{m}^{i_m}\\n    \\\\end{array}\\n\\\\right |\\n\\\\cdot\\n\\\\left |\\n    \\\\begin{array}{ccc}\\n        a_{i_1}^{1} & \\\\cdots & a_{i_m}^{1} \\\\\\\\\\n           \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        a_{i_1}^{m} & \\\\cdots & a_{i_m}^{m}\\n    \\\\end{array}\\n\\\\right |\\n\\n\\\\omega_{1} \\\\wedge \\\\cdots \\\\wedge \\\\omega_{m}\\n\\\\end{aligned}\\n$$\\n\\n\u6B64\u5916\\n\\n$$\\n(\\\\bigwedge^m (f \\\\circ g))(\\\\omega_{1} \\\\wedge \\\\cdots \\\\wedge \\\\omega_{m})\\n= \\\\left |\\n    \\\\begin{array}{ccc}\\n        c_1^1 & \\\\cdots & c_m^1 \\\\\\\\\\n           \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        c_1^m & \\\\cdots & c_m^m\\n    \\\\end{array}\\n\\\\right |\\n\\\\omega_{1} \\\\wedge \\\\cdots \\\\wedge \\\\omega_{m}\\n$$\\n\\n\u6700\u7EC8\u53EF\u5F97\\n\\n$$\\n\\\\left |\\n    \\\\begin{array}{ccc}\\n        c_1^1 & \\\\cdots & c_m^1 \\\\\\\\\\n           \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        c_1^m & \\\\cdots & c_m^m\\n    \\\\end{array}\\n\\\\right |\\n\\\\omega_{1} \\\\wedge \\\\cdots \\\\wedge \\\\omega_{m}\\n=\\n\\\\sum \\\\limits_{1 \\\\le i_i < \\\\cdots < i_m \\\\le n}\\n\\\\left |\\n    \\\\begin{array}{ccc}\\n        b_{1}^{i_1} & \\\\cdots & b_{m}^{i_1} \\\\\\\\\\n        \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        b_{1}^{i_m} & \\\\cdots & b_{m}^{i_m}\\n    \\\\end{array}\\n\\\\right |\\n\\\\cdot\\n\\\\left |\\n    \\\\begin{array}{ccc}\\n        a_{i_1}^{1} & \\\\cdots & a_{i_m}^{1} \\\\\\\\\\n           \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        a_{i_1}^{m} & \\\\cdots & a_{i_m}^{m}\\n    \\\\end{array}\\n\\\\right |\\n\\\\omega_{1} \\\\wedge \\\\cdots \\\\wedge \\\\omega_{m}\\n$$\\n\\n\u6240\u4EE5\\n\\n$$\\ndet(AB) =\\n\\\\left |\\n    \\\\begin{array}{ccc}\\n        c_1^1 & \\\\cdots & c_1^m \\\\\\\\\\n           \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        c_m^1 & \\\\cdots & c_m^m\\n    \\\\end{array}\\n\\\\right |\\n=\\n\\\\sum \\\\limits_{1 \\\\le i_i < \\\\cdots < i_m \\\\le n}\\n\\\\left |\\n    \\\\begin{array}{ccc}\\n        a_{i_1}^{1} & \\\\cdots & a_{i_m}^{1} \\\\\\\\\\n           \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        a_{i_1}^{m} & \\\\cdots & a_{i_m}^{m}\\n    \\\\end{array}\\n\\\\right |\\n\\\\cdot\\n\\\\left |\\n    \\\\begin{array}{ccc}\\n        b_{1}^{i_1} & \\\\cdots & b_{m}^{i_1} \\\\\\\\\\n        \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        b_{1}^{i_m} & \\\\cdots & b_{m}^{i_m}\\n    \\\\end{array}\\n\\\\right |\\n$$\\n\\n\u7279\u522B\u5F97\uFF0C\u5F53$m=n$\u65F6\uFF0C\u53EF\u4EE5\u5F97\u5230\\n\\n$$\\ndet(AB) =\\n\\\\left |\\n    \\\\begin{array}{ccc}\\n        a_{1}^{1} & \\\\cdots & a_{m}^{1} \\\\\\\\\\n           \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        a_{1}^{m} & \\\\cdots & a_{m}^{m}\\n    \\\\end{array}\\n\\\\right |\\n\\\\cdot\\n\\\\left |\\n    \\\\begin{array}{ccc}\\n        b_{1}^{1} & \\\\cdots & b_{m}^{1} \\\\\\\\\\n        \\\\vdots & \\\\ddots & \\\\vdots \\\\\\\\\\n        b_{1}^{m} & \\\\cdots & b_{m}^{m}\\n    \\\\end{array}\\n\\\\right |\\n=detA \\\\cdot detB\\n$$"},{"id":"classic-machine-learning-algorithms","metadata":{"permalink":"/classic-machine-learning-algorithms","source":"@site/blog/2021-10-10-classic-machine-learning-algorithms/index.mdx","title":"\u7ECF\u5178\u673A\u5668\u5B66\u4E60\u7B97\u6CD5\u7684\u6781\u7B80\u5B9E\u73B0","description":"Banner","date":"2021-10-10T00:00:00.000Z","tags":[{"inline":false,"label":"\u673A\u5668\u5B66\u4E60","permalink":"/tags/ml","description":"\u4E00\u4E9B\u673A\u5668\u5B66\u4E60\u76F8\u5173\u7684\u6587\u7AE0"},{"inline":false,"label":"Python","permalink":"/tags/python","description":"\u4E00\u4E9BPython\u76F8\u5173\u7684\u6587\u7AE0"}],"readingTime":5.77,"hasTruncateMarker":true,"authors":[{"name":"Kun Luo","title":"Software Engineer","url":"https://github.com/luokn","page":{"permalink":"/authors/luokun"},"socials":{"github":"https://github.com/luokn","zhihu":"https://www.zhihu.com/people/luokn","email":"mailto:luokun485@gmail.com"},"imageURL":"/img/avatar.jpg","key":"luokun"}],"frontMatter":{"slug":"classic-machine-learning-algorithms","title":"\u7ECF\u5178\u673A\u5668\u5B66\u4E60\u7B97\u6CD5\u7684\u6781\u7B80\u5B9E\u73B0","authors":"luokun","tags":["ml","python"]},"unlisted":false,"prevItem":{"title":"\u67EF\u897F-\u6BD4\u5185\u516C\u5F0F\u8BC1\u660E","permalink":"/proof-of-cauchy-binet-formula"}},"content":"![Banner](./banner.jpg \\"Banner\\")\\n\\n> \u5927\u4E09\u65F6\u66FE\u82B1\u4E24\u5468\u65F6\u95F4\u96C6\u4E2D\u5B66\u4E60\u7ECF\u5178\u673A\u5668\u5B66\u4E60\u7B97\u6CD5\uFF1A\u767D\u5929\u5BF9\u7167\u674E\u822A\u8001\u5E08\u7684\u300A\u7EDF\u8BA1\u5B66\u4E60\u65B9\u6CD5\u300B\u63A8\u5BFC\u516C\u5F0F\uFF0C\u665A\u4E0A\u628A\u516C\u5F0F\u4E00\u884C\u884C\u5199\u6210\u4EE3\u7801\u3002\\n> \u5728\u53C2\u8003 GitHub \u4E0A\u73B0\u6709\u5B9E\u73B0\u65F6\uFF0C\u6211\u53D1\u73B0\u5F88\u591A\u4EE3\u7801\u4E3A\u4E86\u8FFD\u6C42\u201C\u5DE5\u7A0B\u5316\u201D\u800C\u53D8\u5F97\u5197\u957F\uFF0C\u53CD\u800C\u63A9\u76D6\u4E86\u7B97\u6CD5\u672C\u8EAB\u7684\u6838\u5FC3\u601D\u60F3\u3002\\n> \u4E8E\u662F\u6211\u628A\u81EA\u5DF1\u7684\u5B9E\u73B0\u6574\u7406\u51FA\u6765\uFF0C\u5C3D\u91CF\u4FDD\u6301**\u6781\u7B80\u3001\u53EF\u8BFB\u3001\u53EF\u8FD0\u884C**\uFF0C\u5E0C\u671B\u80FD\u5E2E\u52A9\u5927\u5BB6\u5FEB\u901F\u7406\u89E3\u7B97\u6CD5\u539F\u7406\u3002\\n>\\n> \u9879\u76EE\u5730\u5740\uFF1A[![GitHub](https://img.shields.io/badge/GitHub-luokn%2Fml-181717?logo=github)](https://github.com/luokn/ml)\\n> ![Stars](https://img.shields.io/github/stars/luokn/ml)\\n\\n{/* truncate */}\\n\\n## \u5199\u5728\u524D\u9762\\n\\n\u8FD9\u5957\u5B9E\u73B0\u6709\u51E0\u4E2A\u7279\u70B9\uFF1A\\n\\n- **\u96F6\u4F9D\u8D56**\uFF1A\u9664 NumPy\u3001Matplotlib \u548C SciPy \u5916\uFF0C\u4E0D\u8C03\u7528\u4EFB\u4F55\u673A\u5668\u5B66\u4E60\u5E93\uFF1B\\n- **\u4EE3\u7801\u6781\u7B80**\uFF1A\u6BCF\u4E2A\u7B97\u6CD5\u90FD\u538B\u7F29\u5230\u6700\u6838\u5FC3\u7684\u51E0\u5341\u884C\uFF0C\u65B9\u4FBF\u5BF9\u7167\u516C\u5F0F\u9605\u8BFB\uFF1B\\n- **\u9644\u5E26\u53EF\u89C6\u5316**\uFF1A\u5927\u90E8\u5206\u7B97\u6CD5\u90FD\u914D\u4E86\u751F\u6210\u6570\u636E\u548C\u7ED8\u5236\u7ED3\u679C\u7684\u811A\u672C\uFF0C\u8DD1\u8D77\u6765\u5C31\u80FD\u770B\u5230\u6548\u679C\uFF1B\\n- **\u5BF9\u5E94\u6559\u6750**\uFF1A\u5B9E\u73B0\u601D\u8DEF\u4E3B\u8981\u53C2\u8003\u300A\u7EDF\u8BA1\u5B66\u4E60\u65B9\u6CD5\u300B\uFF0C\u9002\u5408\u8FB9\u770B\u4E66\u8FB9\u6572\u4EE3\u7801\u3002\\n\\n\u5F53\u7136\uFF0C\u8FD9\u79CD\u5199\u6CD5**\u91CD\u5728\u6559\u5B66\uFF0C\u4E0D\u8FFD\u6C42\u5DE5\u4E1A\u7EA7\u6548\u7387**\u3002\u7406\u89E3\u4E86\u539F\u7406\u4E4B\u540E\uFF0C\u5B9E\u9645\u9879\u76EE\u4E2D\u8FD8\u662F\u5EFA\u8BAE\u4F7F\u7528 scikit-learn\u3001XGBoost\u3001PyTorch \u7B49\u6210\u719F\u5DE5\u5177\u3002\\n\\n## \u7B97\u6CD5\u4E00\u89C8\\n\\n\u76EE\u524D\u5DF2\u5B9E\u73B0 12 \u4E2A\u7ECF\u5178\u7B97\u6CD5\uFF0C\u8986\u76D6\u76D1\u7763\u5B66\u4E60\u3001\u65E0\u76D1\u7763\u5B66\u4E60\u548C\u6982\u7387\u6A21\u578B\u4E09\u5927\u7C7B\uFF1A\\n\\n| \u7B97\u6CD5 | \u7C7B\u578B | \u6838\u5FC3\u601D\u60F3 | \u6E90\u7801 |\\n| :--- | :--- | :--- | :--- |\\n| **AdaBoost** | \u96C6\u6210\u5B66\u4E60 | \u4E32\u884C\u8BAD\u7EC3\u5F31\u5206\u7C7B\u5668\uFF0C\u91CD\u70B9\u5173\u6CE8\u4E0A\u4E00\u8F6E\u5206\u9519\u7684\u6837\u672C | [adaboost.py](https://github.com/luokn/ml/blob/master/src/adaboost.py) |\\n| **Decision Tree** | \u76D1\u7763\u5B66\u4E60 | \u7528\u4FE1\u606F\u589E\u76CA\u9012\u5F52\u9009\u62E9\u7279\u5F81\uFF0C\u6784\u5EFA\u6811\u5F62\u51B3\u7B56\u89C4\u5219 | [decision_tree.py](https://github.com/luokn/ml/blob/master/src/decision_tree.py) |\\n| **EM** | \u6982\u7387\u6A21\u578B | \u671F\u671B\u6700\u5927\u5316\uFF0C\u7528\u4E09\u786C\u5E01\u6A21\u578B\u6F14\u793A\u9690\u53D8\u91CF\u6C42\u89E3 | [em.py](https://github.com/luokn/ml/blob/master/src/em.py) |\\n| **GMM** | \u65E0\u76D1\u7763\u5B66\u4E60 | \u9AD8\u65AF\u6DF7\u5408\u6A21\u578B + EM \u7B97\u6CD5\u5B9E\u73B0\u8F6F\u805A\u7C7B | [gmm.py](https://github.com/luokn/ml/blob/master/src/gmm.py) |\\n| **K-Means** | \u65E0\u76D1\u7763\u5B66\u4E60 | \u8FED\u4EE3\u66F4\u65B0\u805A\u7C7B\u4E2D\u5FC3\uFF0C\u6700\u5C0F\u5316\u6837\u672C\u5230\u4E2D\u5FC3\u7684\u8DDD\u79BB | [kmeans.py](https://github.com/luokn/ml/blob/master/src/kmeans.py) |\\n| **KNN** | \u76D1\u7763\u5B66\u4E60 | \u7528\u6700\u8FD1 $k$ \u4E2A\u90BB\u5C45\u7684\u591A\u6570\u6807\u7B7E\u51B3\u5B9A\u65B0\u6837\u672C\u7C7B\u522B | [knn.py](https://github.com/luokn/ml/blob/master/src/knn.py) |\\n| **LDA** | \u964D\u7EF4 / \u5206\u7C7B | \u6700\u5927\u5316\u7C7B\u95F4\u6563\u5EA6\u3001\u6700\u5C0F\u5316\u7C7B\u5185\u6563\u5EA6\uFF0C\u5BFB\u627E\u6700\u4F73\u6295\u5F71\u65B9\u5411 | [lda.py](https://github.com/luokn/ml/blob/master/src/lda.py) |\\n| **Logistic Regression** | \u76D1\u7763\u5B66\u4E60 | \u7528 sigmoid \u5EFA\u6A21\u6982\u7387\uFF0C\u901A\u8FC7\u68AF\u5EA6\u4E0B\u964D\u4F18\u5316\u4EA4\u53C9\u71B5 | [logistic_regression.py](https://github.com/luokn/ml/blob/master/src/logistic_regression.py) |\\n| **Naive Bayes** | \u76D1\u7763\u5B66\u4E60 | \u5047\u8BBE\u7279\u5F81\u6761\u4EF6\u72EC\u7ACB\uFF0C\u7528\u8D1D\u53F6\u65AF\u4F30\u8BA1\u8BA1\u7B97\u540E\u9A8C\u6982\u7387 | [naive_bayes.py](https://github.com/luokn/ml/blob/master/src/naive_bayes.py) |\\n| **PCA** | \u964D\u7EF4 | \u5BF9\u534F\u65B9\u5DEE\u77E9\u9635\u7279\u5F81\u503C\u5206\u89E3\uFF0C\u4FDD\u7559\u65B9\u5DEE\u6700\u5927\u7684\u65B9\u5411 | [pca.py](https://github.com/luokn/ml/blob/master/src/pca.py) |\\n| **Perceptron** | \u76D1\u7763\u5B66\u4E60 | \u5728\u7EBF\u66F4\u65B0\u6743\u91CD\uFF0C\u76F4\u5230\u6240\u6709\u6837\u672C\u88AB\u6B63\u786E\u5206\u7C7B | [perceptron.py](https://github.com/luokn/ml/blob/master/src/perceptron.py) |\\n| **SVM** | \u76D1\u7763\u5B66\u4E60 | SMO \u6C42\u89E3\u5BF9\u5076\u95EE\u9898\uFF0C\u652F\u6301\u7EBF\u6027/\u591A\u9879\u5F0F/RBF \u6838 | [svm.py](https://github.com/luokn/ml/blob/master/src/svm.py) |\\n\\n\u6B64\u5916\u8FD8\u6709\u4E00\u4E2A **Multinomial Logistic Regression** \u7684\u5B9E\u73B0\uFF0C\u7528\u4E8E\u591A\u5206\u7C7B\u4EFB\u52A1\uFF1A[multi_logistic_regression.py](https://github.com/luokn/ml/blob/master/src/multi_logistic_regression.py)\u3002\\n\\n## \u6838\u5FC3\u4EE3\u7801\u7247\u6BB5\\n\\n\u4E0B\u9762\u6311\u9009\u4E09\u4E2A\u6700\u5177\u4EE3\u8868\u6027\u7684\u7B97\u6CD5\uFF0C\u5C55\u793A\u5B83\u4EEC\u7684\u201C\u9AA8\u67B6\u201D\u5B9E\u73B0\u3002\\n\\n### PCA\uFF1A\u4E3B\u6210\u5206\u5206\u6790\\n\\nPCA \u7684\u6838\u5FC3\u53EA\u6709\u4E09\u6B65\uFF1A\u53BB\u4E2D\u5FC3\u5316 \u2192 \u534F\u65B9\u5DEE\u77E9\u9635\u7279\u5F81\u503C\u5206\u89E3 \u2192 \u53D6\u524D $k$ \u5927\u7279\u5F81\u503C\u5BF9\u5E94\u7684\u7279\u5F81\u5411\u91CF\u3002\\n\\n```python\\nclass PCA:\\n    def __init__(self, k: int):\\n        self.k = k\\n\\n    def __call__(self, X: np.ndarray):\\n        X_norm = X - X.mean(axis=0)               # 1. \u53BB\u4E2D\u5FC3\u5316\\n        L, V = np.linalg.eig(X_norm.T @ X_norm)   # 2. \u534F\u65B9\u5DEE\u77E9\u9635\u7279\u5F81\u503C\u5206\u89E3\\n        topk = np.argsort(L)[::-1][: self.k]      # 3. \u524D k \u5927\u7279\u5F81\u503C\u7D22\u5F15\\n        return X_norm @ V[:, topk]                # 4. \u6295\u5F71\u5230\u4F4E\u7EF4\u7A7A\u95F4\\n```\\n\\n### Perceptron\uFF1A\u611F\u77E5\u673A\\n\\n\u611F\u77E5\u673A\u662F\u795E\u7ECF\u7F51\u7EDC\u7684\u201C\u9F3B\u7956\u201D\u3002\u5B83\u9010\u4E2A\u6837\u672C\u68C0\u67E5\u662F\u5426\u5206\u7C7B\u6B63\u786E\uFF0C\u82E5\u9519\u8BEF\u5219\u6CBF\u8D1F\u68AF\u5EA6\u65B9\u5411\u66F4\u65B0\u6743\u91CD\u3002\\n\\n```python\\nclass Perceptron:\\n    def __init__(self, input_dim: int, lr=5e-4):\\n        self.weights = np.random.randn(input_dim + 1)  # \u5305\u542B\u504F\u7F6E\\n        self.lr = lr\\n\\n    def fit(self, X: np.ndarray, y: np.ndarray):\\n        for x, y in zip(pad(X), y):\\n            if y * (x @ self.weights) <= 0:        # \u5206\u7C7B\u9519\u8BEF\\n                neg_grad = x * y                    # \u8BA1\u7B97\u8D1F\u68AF\u5EA6\\n                self.weights += self.lr * neg_grad  # \u6CBF\u8D1F\u68AF\u5EA6\u66F4\u65B0\\n\\n    def __call__(self, X: np.ndarray) -> np.ndarray:\\n        y_pred = pad(X) @ self.weights\\n        return np.where(y_pred > 0, 1, -1)\\n```\\n\\n### Logistic Regression\uFF1A\u903B\u8F91\u65AF\u8482\u56DE\u5F52\\n\\n\u903B\u8F91\u56DE\u5F52\u7528 sigmoid \u628A\u7EBF\u6027\u8F93\u51FA\u6620\u5C04\u4E3A\u6982\u7387\uFF0C\u518D\u7528\u68AF\u5EA6\u4E0B\u964D\u6700\u5C0F\u5316\u4EA4\u53C9\u71B5\u635F\u5931\u3002\\n\\n```python\\nclass LogisticRegression:\\n    def __init__(self, input_dim: int, lr=5e-4):\\n        self.weights = np.random.randn(input_dim + 1)\\n        self.lr = lr\\n\\n    def fit(self, X: np.ndarray, y: np.ndarray):\\n        X_pad = pad(X)\\n        pred = sigmoid(X_pad @ self.weights)         # \u9884\u6D4B\u6982\u7387\\n        grad = X_pad.T @ (pred - y) / len(pred)      # \u4EA4\u53C9\u71B5\u68AF\u5EA6\\n        self.weights -= self.lr * grad               # \u53C2\u6570\u66F4\u65B0\\n\\n    def __call__(self, X: np.ndarray) -> np.ndarray:\\n        y_pred = sigmoid(pad(X) @ self.weights)\\n        return np.where(y_pred > 0.5, 1, 0)\\n```\\n\\n\u5982\u679C\u60F3\u770B\u66F4\u5B8C\u6574\u7684\u5B9E\u73B0\uFF08\u5982 SVM \u7684 SMO\u3001\u51B3\u7B56\u6811\u7684\u4FE1\u606F\u589E\u76CA\u3001GMM \u7684 EM \u8FED\u4EE3\u7B49\uFF09\uFF0C\u53EF\u4EE5\u76F4\u63A5\u70B9\u8FDB\u4E0A\u9762\u7684\u6E90\u7801\u94FE\u63A5\uFF0C\u6BCF\u4E2A\u6587\u4EF6\u90FD\u662F\u72EC\u7ACB\u53EF\u8FD0\u884C\u7684\u3002\\n\\n## \u53EF\u89C6\u5316\u6548\u679C\\n\\n\u4E0B\u9762\u662F\u4E00\u90E8\u5206\u7B97\u6CD5\u7684\u8FD0\u884C\u7ED3\u679C\u3002\u4E3A\u4E86\u4FBF\u4E8E\u5BF9\u7167\uFF0C\u6BCF\u5E45\u56FE\u90FD\u5305\u542B\u539F\u59CB\u6570\u636E\u5206\u5E03\u4E0E\u7B97\u6CD5\u8F93\u51FA\u3002\\n\\n### \u76D1\u7763\u5B66\u4E60\\n\\n| \u7B97\u6CD5 | \u53EF\u89C6\u5316 |\\n| :--- | :--- |\\n| **AdaBoost** | ![AdaBoost](./adaboost.png \\"AdaBoost\\") |\\n| **KNN** | ![KNN](./knn.png \\"KNN\\") |\\n| **Logistic Regression** | ![Logistic Regression](./logistic_regression.gif \\"Logistic Regression\\") |\\n| **Perceptron** | ![Perceptron](./perceptron.gif \\"Perceptron\\") |\\n| **SVM** | ![SVM](./svm.png \\"SVM\\") |\\n\\n### \u65E0\u76D1\u7763\u5B66\u4E60\u4E0E\u964D\u7EF4\\n\\n| \u7B97\u6CD5 | \u53EF\u89C6\u5316 |\\n| :--- | :--- |\\n| **PCA** | ![PCA](./pca.png \\"PCA\\") |\\n| **LDA** | ![LDA](./lda.png \\"LDA\\") |\\n| **GMM** | ![GMM](./gmm.png \\"GMM\\") |\\n| **K-Means** | ![K-Means](./kmeans.gif \\"K-Means\\") |\\n\\n\u8FD9\u4E9B\u56FE\u90FD\u662F\u76F4\u63A5\u8FD0\u884C\u5BF9\u5E94 `.py` \u6587\u4EF6\u751F\u6210\u7684\u3002\u4F8B\u5982\uFF1A\\n\\n```bash\\ngit clone https://github.com/luokn/ml.git\\ncd ml/src\\npython pca.py\\npython kmeans.py\\npython svm.py\\n```\\n\\n## \u4E00\u70B9\u5B66\u4E60\u5FC3\u5F97\\n\\n\u521D\u5B66\u673A\u5668\u5B66\u4E60\u65F6\uFF0C\u5F88\u5BB9\u6613\u88AB\u5404\u79CD\u6846\u67B6\u548C\u8C03\u53C2\u6280\u5DE7\u7ED5\u8FDB\u53BB\u3002\u6211\u7684\u4F53\u4F1A\u662F\uFF1A**\u5148\u56DE\u5230\u516C\u5F0F\uFF0C\u518D\u7528\u6700\u77ED\u7684\u4EE3\u7801\u628A\u5B83\u5B9E\u73B0\u51FA\u6765**\uFF0C\u8FDC\u6BD4\u76F4\u63A5\u8C03\u5305\u6765\u5F97\u624E\u5B9E\u3002\\n\\n\u4F8B\u5982\uFF0C\u5F53\u4F60\u4EB2\u624B\u5199\u8FC7 SVM \u7684 SMO\u3001\u5199\u8FC7 GMM \u7684 EM\u3001\u5199\u8FC7\u51B3\u7B56\u6811\u7684\u4FE1\u606F\u589E\u76CA\uFF0C\u4F60\u5C31\u4F1A\u771F\u6B63\u7406\u89E3\uFF1A\\n\\n- \u4E3A\u4EC0\u4E48 SVM \u53EA\u4F9D\u8D56\u652F\u6301\u5411\u91CF\uFF1B\\n- \u4E3A\u4EC0\u4E48 EM \u7B97\u6CD5\u8981\u4EA4\u66FF\u8FDB\u884C E \u6B65\u548C M \u6B65\uFF1B\\n- \u4E3A\u4EC0\u4E48\u51B3\u7B56\u6811\u5BB9\u6613\u8FC7\u62DF\u5408\uFF0C\u9700\u8981\u526A\u679D\u6216\u9650\u5236\u6DF1\u5EA6\u3002\\n\\n\u8FD9\u5957\u4EE3\u7801\u5C31\u662F\u6211\u5F53\u65F6\u201C\u5543\u201D\u300A\u7EDF\u8BA1\u5B66\u4E60\u65B9\u6CD5\u300B\u7684\u526F\u4EA7\u54C1\u3002\u5E0C\u671B\u5B83\u4E5F\u80FD\u6210\u4E3A\u4F60\u5165\u95E8\u673A\u5668\u5B66\u4E60\u8DEF\u4E0A\u7684\u4E00\u5757\u57AB\u811A\u77F3\u3002\\n\\n## \u76F8\u5173\u94FE\u63A5\\n\\n- **GitHub \u4ED3\u5E93**\uFF1A[luokn/ml](https://github.com/luokn/ml)\\n- **\u53C2\u8003\u6559\u6750**\uFF1A\u300A\u7EDF\u8BA1\u5B66\u4E60\u65B9\u6CD5\u300B\uFF08\u674E\u822A \u8457\uFF09\\n\\n\u5982\u679C\u4F60\u53D1\u73B0\u4EE3\u7801\u4E2D\u6709\u53EF\u4EE5\u8FDB\u4E00\u6B65\u7B80\u5316\u7684\u5730\u65B9\uFF0C\u6216\u8005\u6709\u7B97\u6CD5\u60F3\u8865\u5145\uFF0C\u6B22\u8FCE\u5728\u4ED3\u5E93\u91CC\u63D0 Issue \u6216 PR\u3002"}]}}')}}]);